import { useState, useEffect } from "react";

// ─── DAILY COACH — discipline, wealth, wisdom, leadership, family ────────────
const COACH_KEY = "axiom_coach_v1";

// منهج تدريبي — 30 درساً عبر 6 ركائز. درس كل يوم.
const COACH_LESSONS = [
  // ── الانضباط ──
  { pillar:"الانضباط", icon:"🧱", color:"#3b82f6", title:"قاعدة الخمس ثوانٍ", teach:"في اللحظة التي تشعر فيها بالتردد، عُدّ 5-4-3-2-1 ثم تحرّك فوراً. التردد هو المكان الذي يموت فيه الانضباط. عقلك يحاول حمايتك من الانزعاج، لكن النمو كله خلف هذا الانزعاج.", practice:"اليوم، أول مرة تريد أن تؤجّل شيئاً — عُدّ تنازلياً وابدأ خلال 5 ثوانٍ.", mantra:"الفعل يسبق الشعور، لا العكس." },
  { pillar:"الانضباط", icon:"🧱", color:"#3b82f6", title:"اربح الصباح", teach:"الطريقة التي تبدأ بها تحدّد إيقاع يومك كله. الساعة الأولى تتنبأ بباقي اليوم. لا تلمس الهاتف قبل أن تنجز شيئاً نافعاً — لأن أول ما تطعمه عقلك هو ما يحكمه.", practice:"لا هاتف في أول 30 دقيقة. اشرب ماءً، تحرّك، ثم ابدأ مهمتك الأولى.", mantra:"من ملك صباحه ملك يومه." },
  { pillar:"الانضباط", icon:"🧱", color:"#3b82f6", title:"افعل الشيء المُمِلّ", teach:"النجاح مُمِلّ. هو تكرار نفس الأفعال الصحيحة حين لا يصفّق لك أحد. الحماس يزول، أما الأنظمة فتبقى. العظماء يفعلون ما يكرهه الكسالى بانتظام.", practice:"اختر المهمة المملّة التي تتهرّب منها، وافعلها أولاً اليوم.", mantra:"الانضباط جسر بين الأهداف والإنجاز." },
  { pillar:"الانضباط", icon:"🧱", color:"#3b82f6", title:"اقطع المشتتات", teach:"لا يمكنك التركيز وأنت غارق في الإشعارات. انتباهك هو أثمن ما تملك — احرسه بلا رحمة. كل تنبيه يسرق منك جزءاً من عقلك لا يعود.", practice:"ضع الهاتف على وضع 'عدم الإزعاج' لساعتين من العمل العميق اليوم.", mantra:"حيث يذهب انتباهك تذهب حياتك." },
  { pillar:"الانضباط", icon:"🧱", color:"#3b82f6", title:"أوفِ بوعدك لنفسك", teach:"كل وعد تكسره مع نفسك يدرّب عقلك على ألا يثق بك. الوعود الصغيرة المحفوظة تبني ثقة لا تُهزم بالنفس. كن رجلاً تثق به أنت أولاً.", practice:"اقطع وعداً صغيراً هذا الصباح والتزم به مهما حدث.", mantra:"ثقتك بنفسك تُبنى من وعود صغيرة محفوظة." },

  // ── المال ──
  { pillar:"المال", icon:"💰", color:"#22d47e", title:"ادفع لنفسك أولاً", teach:"الثروة ليست ما تكسبه بل ما تحتفظ به. ادّخر واستثمر قبل أن تنفق، لا بعده. من ينفق أولاً ويدّخر ما تبقّى لا يتبقّى له شيء أبداً.", practice:"حوّل مبلغاً للادخار/الاستثمار اليوم قبل أي إنفاق.", mantra:"ليست العبرة بما تكسب بل بما تبقي." },
  { pillar:"المال", icon:"💰", color:"#22d47e", title:"خسائر صغيرة، أرباح كبيرة", teach:"تصبح غنياً بقطع الخاسر بسرعة وترك الرابح يجري. البقاء أولاً ثم النمو. صفقة سيئة واحدة بلا وقف خسارة تمحو عشر صفقات جيدة.", practice:"راجع كل صفقاتك المفتوحة — اقطع أي شيء تحت وقف الخسارة. بلا استثناء.", mantra:"اقطع الخاسر بسرعة، واترك الرابح يجري." },
  { pillar:"المال", icon:"💰", color:"#22d47e", title:"الصبر يُثمر", teach:"السوق ينقل المال من قليل الصبر إلى صاحب الصبر. أغلب الأرباح تُصنع بالجلوس لا بالتداول. التداول الزائد عدوّك الأول.", practice:"لا تأخذ أي صفقة اندفاعية اليوم. فقط إشارات الضوء الأخضر الممتازة أو لا شيء.", mantra:"المال يُصنع بالانتظار لا بالحركة." },
  { pillar:"المال", icon:"💰", color:"#22d47e", title:"اعرف أرقامك", teach:"لا يمكنك تنمية ما لا تقيسه. الأثرياء يعرفون سيولتهم وهوامشهم ومصاريفهم عن ظهر قلب. الجهل بأرقامك هو بداية إفلاسك.", practice:"اكتب وضع السيولة لديك ورقماً مهماً واحداً في عملك.", mantra:"ما لا يُقاس لا يُنمّى." },
  { pillar:"المال", icon:"💰", color:"#22d47e", title:"الفائدة المركّبة ملك", teach:"دولار واحد يُستثمر بانتظام يهزم مئة دولار تُستثمر مرة واحدة. الاتساق المُمِلّ عبر السنين يبني الثروات. الوقت أقوى من المبلغ.", practice:"أنشئ أو أضف إلى استثمار دوري تلقائي واحد اليوم.", mantra:"الثبات الصغير عبر الزمن يصنع المعجزات." },

  // ── الحكمة ──
  { pillar:"الحكمة", icon:"🦉", color:"#a855f7", title:"استجب ولا تتفاعل", teach:"بين المثير والاستجابة فجوة، وفي تلك الفجوة قوتك وحريتك. توقّف قبل أن تتصرف أو تتكلم. ردّ الفعل السريع نادراً ما يكون حكيماً.", practice:"قبل أي قرار أو ردّ مهم اليوم، خذ 5 أنفاس أولاً.", mantra:"بين الغضب والكلمة ثانية تصنع الفرق." },
  { pillar:"الحكمة", icon:"🦉", color:"#a855f7", title:"افهم قبل أن تُفهَم", teach:"أغلب الخلافات مجرّد شخصين يريد كلٌّ منهما أن يُسمع. أنصت تماماً قبل أن ترد. حين يشعر الآخر أنك فهمته، يلين قلبه.", practice:"في خلافك القادم، أعِد صياغة وجهة نظره قبل أن تعطي وجهة نظرك.", mantra:"الإنصات أقوى من الإقناع." },
  { pillar:"الحكمة", icon:"🦉", color:"#a855f7", title:"ماذا يفعل أحكمُ نسخة منك؟", teach:"حين تتحيّر، اسأل: ماذا تفعل أفضل نسخة مني الآن؟ ثم افعلها. أنت تعرف الجواب غالباً، لكنك تتجنّبه.", practice:"واجه قراراً صعباً اليوم بسؤال: 'ماذا يفعل الحكيم؟'", mantra:"الحكمة أن تفعل ما تعرفه أصلاً." },
  { pillar:"الحكمة", icon:"🦉", color:"#a855f7", title:"الامتنان يُعيد برمجتك", teach:"لا يمكنك أن تكون قلقاً وممتنّاً في آنٍ واحد. الامتنان انضباط لا شعور — تختاره حتى في الأيام الصعبة. القلب الشاكر لا يعرف اليأس.", practice:"اذكر 3 أشياء محددة أنت ممتنّ لها قبل أن تنام.", mantra:"الشاكر لا يعرف القلق." },
  { pillar:"الحكمة", icon:"🦉", color:"#a855f7", title:"الزم طريقك", teach:"المقارنة تسرق الفرح وتعمي البصيرة. اركض سباقك أنت؛ منافسك الوحيد هو نسختك بالأمس. ما تراه عند غيرك واجهة، وما تعيشه أنت حقيقة.", practice:"لاحظ متى تقارن نفسك اليوم — وأعِد توجيه نظرك إلى تقدّمك أنت.", mantra:"منافسك الوحيد هو أنت بالأمس." },

  // ── القيادة ──
  { pillar:"القيادة", icon:"👑", color:"#f59e0b", title:"قُد بالهدوء", teach:"من حولك (وأهلك) يشعرون بطاقتك قبل كلماتك. القائد الهادئ يصنع غرفة هادئة. توترك يَعدي، وسكينتك تَعدي أيضاً.", practice:"في لحظتك المتوترة القادمة، اخفض صوتك وأبطئ عمداً.", mantra:"القائد الهادئ يصنع فريقاً هادئاً." },
  { pillar:"القيادة", icon:"👑", color:"#f59e0b", title:"المسؤولية الكاملة", teach:"حين يسوء شيء، القائد ينظر في المرآة أولاً. اللوم ضعف، والمسؤولية قوة. حين تمتلك المشكلة تمتلك الحل.", practice:"تحمّل المسؤولية الكاملة عن مشكلة واحدة اليوم — بلا أعذار، فقط الخطوة التالية.", mantra:"امتلك المشكلة تمتلك الحل." },
  { pillar:"القيادة", icon:"👑", color:"#f59e0b", title:"امدح بالتحديد", teach:"المدح العام ضجيج. المدح المحدد يغيّر السلوك ويبني الولاء. قل للناس بالضبط ما أحسنوا فعله.", practice:"امدح شخصاً اليوم على شيء محدد أحسن فعله.", mantra:"ما تلاحظه ينمو." },
  { pillar:"القيادة", icon:"👑", color:"#f59e0b", title:"معيارك هو ما تسكت عنه", teach:"لا تحصل على السلوك الذي تريده، بل على ما تقبله. ارفع معيارك بهدوء بالقدوة لا بالصراخ. ما تتجاهله تسمح به.", practice:"حدّد أمراً تتغاضى عنه منذ مدة، وعالجه بهدوء اليوم.", mantra:"ما تتسامح معه يصبح معيارك." },
  { pillar:"القيادة", icon:"👑", color:"#f59e0b", title:"قرّر ثم تحرّك", teach:"القادة يقرّرون بمعلومات ناقصة ثم يعدّلون. التردد يكلّف أكثر من القرار الخاطئ. لا قرار هو أسوأ قرار.", practice:"اتخذ قراراً أجّلته — اليوم، قبل الظهر.", mantra:"التردد أغلى من الخطأ." },

  // ── الأب ──
  { pillar:"الأب", icon:"👨‍👧", color:"#14b8a6", title:"الحضور قبل الهدايا", teach:"الأطفال يهجّون الحب: و-ق-ت. لن يتذكّروا الهدايا، بل سيتذكّرون إن كنت حاضراً. وجودك الكامل دقيقة أثمن من ساعة مشتّتة.", practice:"15 دقيقة حضور كامل مع أطفالك — الهاتف في غرفة أخرى.", mantra:"الأطفال يهجّون الحب: وقت." },
  { pillar:"الأب", icon:"👨‍👧", color:"#14b8a6", title:"كن الهدوء في عاصفتهم", teach:"ردّ فعلك يعلّمهم كيف يواجهون الدنيا. اثبت حين ينهارون. إن انفعلت معهم تعلّموا الانفعال، وإن هدأت تعلّموا الاتزان.", practice:"حين يغضب طفلك القادم، كن هادئاً وفضولياً بدل الانزعاج.", mantra:"هدوؤك اليوم اتزانهم غداً." },
  { pillar:"الأب", icon:"👨‍👧", color:"#14b8a6", title:"اضبطهم وهم محسنون", teach:"ما تلاحظه ينمو. امدح السلوك الذي تريد رؤيته أكثر. أكثر الآباء يلاحظون الخطأ ويغفلون الصواب.", practice:"اضبط طفلك وهو يفعل شيئاً صحيحاً اليوم وسمِّه بصوت عالٍ.", mantra:"ما تمدحه يتكرّر." },
  { pillar:"الأب", icon:"👨‍👧", color:"#14b8a6", title:"يصبحون ما يرون", teach:"الأطفال يفعلون ما تفعل لا ما تقول. أنت تعلّم دائماً — فاحرص أن يكون الدرس صحيحاً. قدوتك أبلغ من ألف نصيحة.", practice:"اقتدِ بعادة واحدة اليوم تودّ أن يقلّدها أبناؤك.", mantra:"أبناؤك مرآتك." },
  { pillar:"الأب", icon:"👨‍👧", color:"#14b8a6", title:"اسأل ثم أنصت", teach:"سؤال صادق وإنصات حقيقي يبنيان صلة أعمق من ساعة من الكلام عليهم. أعطهم أذنك لا لسانك.", practice:"اسأل طفلك سؤالاً مفتوحاً اليوم وأنصت فقط — بلا إصلاح.", mantra:"أنصت لهم يفتحوا لك قلوبهم." },

  // ── الزوج ──
  { pillar:"الزوج", icon:"❤️", color:"#ef4444", title:"لا تتوقّف عن مغازلتها", teach:"الزواج يموت من الإهمال لا من الخلاف. استمر في مغازلة زوجتك كأنك ما زلت تحاول كسب قلبها. ما كسبته بالاهتمام يحفظه الاهتمام.", practice:"افعل شيئاً صغيراً لتسعد زوجتك اليوم — رسالة، اتصال، خطة لقاء.", mantra:"الحب يُسقى كل يوم وإلا ذبل." },
  { pillar:"الزوج", icon:"❤️", color:"#ef4444", title:"قُل تقديرك بصوت عالٍ", teach:"هي لا تقرأ أفكارك. الامتنان الصامت بلا قيمة. قُله، وبالتحديد. الكلمة الطيبة تبني ما تهدمه أيام الصمت.", practice:"أخبر زوجتك بشيء محدد تقدّره فيها اليوم.", mantra:"التقدير الصامت لا يصل." },
  { pillar:"الزوج", icon:"❤️", color:"#ef4444", title:"أنصت لتفهم لا لتُصلح", teach:"غالباً تريد أن تُسمع لا أن تُحَلّ مشكلتها. اسأل: 'تريدين مساعدة أم فقط أن تتكلمي؟'. أحياناً أذنك أنفع من حلولك.", practice:"حين تشاركك مشكلة، أنصت تماماً قبل أن تقدّم أي حل.", mantra:"أحياناً تريد أذناً لا حلاً." },
  { pillar:"الزوج", icon:"❤️", color:"#ef4444", title:"احمل العبء بصمت", teach:"افعل شيئاً لها دون أن تطلب ودون أن تُعلن. الخدمة حبٌّ في صورة فعل. الرجل الكبير يخدم بلا منّة.", practice:"أنجز عملاً منزلياً أو مهمة لها اليوم دون أن تُطلب منك.", mantra:"الخدمة الصامتة أبلغ حب." },
  { pillar:"الزوج", icon:"❤️", color:"#ef4444", title:"احمِ الصلة", teach:"الهواتف على العشاء تقتل الألفة. احرس اللحظات الصغيرة اليومية — فهي الزواج نفسه. القرب يُبنى من لحظات لا من مناسبات.", practice:"ابعد الهاتف على العشاء، وحادث زوجتك حديثاً كاملاً الليلة.", mantra:"الزواج يُبنى من لحظات صغيرة." },

  // ── كسر العادات ──
  { pillar:"كسر العادات", icon:"🚫", color:"#ef4444", title:"اعرف الشرارة", teach:"كل عادة سيئة لها مُحفِّز — وقت، مكان، شعور، أو شخص. لا تحارب العادة، بل اكتشف ما يُشعلها. حين تعرف الشرارة تملك القدرة على إطفائها قبل أن تشتعل.", practice:"اليوم، حين تنجرّ لعادة سيئة، اكتب ما الذي سبقها مباشرة.", mantra:"اعرف الشرارة تملك النار." },
  { pillar:"كسر العادات", icon:"🚫", color:"#ef4444", title:"اجعلها صعبة", teach:"لا تعتمد على إرادتك، بل على بيئتك. أبعد المُحفِّز خطوة واحدة وتنكسر العادة. الهاتف في غرفة أخرى، الحلوى خارج البيت — العقبة الصغيرة تكفي.", practice:"أبعد شيئاً واحداً يُغذّي عادتك السيئة عن متناول يدك اليوم.", mantra:"بيئتك أقوى من عزيمتك." },
  { pillar:"كسر العادات", icon:"🚫", color:"#ef4444", title:"استبدل لا تحذف", teach:"العقل يكره الفراغ. لا تكتفِ بترك العادة، بل ضع مكانها فعلاً نافعاً يلبّي نفس الحاجة. الفراغ يعيد العادة، والبديل يطردها.", practice:"اختر عادة سيئة وحدّد فعلاً صحياً يحلّ محلّها حين تأتي الرغبة.", mantra:"املأ الفراغ وإلا عاد القديم." },
  { pillar:"كسر العادات", icon:"🚫", color:"#ef4444", title:"قاعدة العشر دقائق", teach:"حين تشتدّ الرغبة، أجّلها عشر دقائق فقط. الرغبة موجة ترتفع ثم تنحسر. إن صبرت قليلاً مرّت. لست مضطراً لرفضها للأبد، فقط الآن.", practice:"عند أول رغبة اليوم، انتظر عشر دقائق قبل أن تستسلم — وراقب كيف تخفّ.", mantra:"الرغبة موجة… انتظرها تنحسر." },
  { pillar:"كسر العادات", icon:"🚫", color:"#ef4444", title:"لا تكسر السلسلة", teach:"كل يوم نظيف حلقة في سلسلة. كلما طالت السلسلة زاد ثمن كسرها. اجعل هدفك ألا تفوّت يومين متتاليين أبداً. الزلّة الواحدة حادث، والزلّتان بداية عودة.", practice:"علّم على يومك النظيف في «عادات تتخلّص منها»، والتزم ألا تكسر السلسلة.", mantra:"لا تفوّت مرتين أبداً." },
  { pillar:"كسر العادات", icon:"🚫", color:"#ef4444", title:"سامح الزلّة وعُد فوراً", teach:"الكمال ليس الهدف، بل العودة السريعة. من يزلّ ثم يجلد نفسه يزلّ أكثر. من يزلّ ثم يعود في الحال ينتصر. الفشل ليس في السقوط بل في البقاء أرضاً.", practice:"إن زللت اليوم، لا تُطل اللوم — عُد إلى المسار في الساعة التالية.", mantra:"العبرة بسرعة العودة لا بعدم السقوط." },

  // ── الشخصية القوية ──
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"قل لا بلا اعتذار", teach:"كل 'نعم' لا تريدها هي 'لا' لنفسك. الرجل القوي يحمي وقته وطاقته بكلمة واضحة بلا تبرير طويل. 'لا' جملة كاملة. من يرضي الجميع يخسر نفسه.", practice:"ارفض اليوم طلباً واحداً لا يخدمك، بوضوح وهدوء وبلا اعتذار.", mantra:"لا تحتاج إذناً لتحمي حدودك." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"لا تطلب الموافقة", teach:"حين تحتاج تصفيق الناس تصبح عبداً لآرائهم. تصرّف من قيمك لا من خوفك مما يقولون. رأيك في نفسك أهم من رأي الجميع فيك.", practice:"اتخذ قراراً اليوم تعرف أنه صحيح حتى لو لم يفهمه من حولك.", mantra:"قيمتك ليست في يد أحد." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"اهدأ تملك الغرفة", teach:"من يثور أولاً يخسر. الهدوء قوة، والانفعال ضعف يُرى. أخفض صوتك وأبطئ كلامك حين يحتدّ الموقف — الثبات يفرض احترامه بلا صياح.", practice:"في أول موقف متوتر اليوم، خذ نفساً واحفظ هدوءك بدل ردّ الفعل.", mantra:"الهادئ يقود، والمنفعل يُقاد." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"كلمتك عقد", teach:"الرجل يساوي كلمته. إن قلت ستفعل، فافعل — وإلا فلا تقل. السمعة تُبنى من وعود صغيرة محفوظة، وتنهار من وعد واحد مكسور.", practice:"لا تقطع اليوم وعداً إلا وأنت عازم على تنفيذه — ثم نفّذه.", mantra:"قيمتك بقدر التزامك بكلمتك." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"واجه ما تخافه", teach:"الخوف يصغر حين تتقدّم نحوه ويكبر حين تهرب. الشجاعة ليست غياب الخوف بل الفعل رغمه. أصعب محادثة أو مهمة هي غالباً بالضبط ما تحتاج فعله.", practice:"افعل اليوم الشيء الواحد الذي تتجنّبه لأنه يخيفك — أولاً.", mantra:"خلف خوفك تنتظر نسختك الأقوى." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"تحمّل المسؤولية كاملة", teach:"الضعيف يلوم الظروف والناس. القوي يقول: 'أنا مسؤول'. حين تملك مشكلتك تملك حلّها. اللوم يمنحك راحة لحظية ويسلبك قوّتك كلها.", practice:"توقّف اليوم عن لوم أي أحد على موقف، واسأل: ما الذي أقدر أن أغيّره أنا؟", mantra:"من يملك المسؤولية يملك القوة." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"اصمت أكثر مما تتكلّم", teach:"الرجل القوي لا يملأ كل صمت بالكلام. الكلام القليل المدروس يحمل ثقلاً أكبر من الثرثرة. حين تتكلّم أقل، يصغي الناس أكثر، ويظنّون فيك عمقاً وثقة.", practice:"في نقاش اليوم، أنصت ضعف ما تتكلّم، ولا تقاطع أحداً.", mantra:"الصمت قوة، والثرثرة تُضعف الهيبة." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"لا تشرح نفسك دائماً", teach:"لست مديناً لأحد بتبرير كل قرار. التفسير الزائد يبدو كاعتذار وضعف. قرارك الواثق لا يحتاج دفاعاً طويلاً. قل ما تريد بوضوح ثم اسكت.", practice:"حين تتخذ قراراً اليوم، اذكر سببك مرة واحدة باختصار، ولا تكرّره دفاعاً.", mantra:"الواثق يقرّر، والمتردّد يبرّر." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"حافظ على رباطة جأشك تحت الضغط", teach:"الأزمات تكشف المعادن. حين يفقد الجميع توازنهم، يبرز القائد بثباته. تدرّب على التنفّس البطيء والكلام الهادئ في اللحظات الصعبة — فالناس تتبع من يبدو مسيطراً.", practice:"في أصعب لحظة اليوم، خذ ٣ أنفاس عميقة قبل أن تتكلّم أو تتصرّف.", mantra:"الضغط يصنع الماس، لا يكسره." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"اضبط لغة جسدك", teach:"جسدك يتكلّم قبل لسانك. الوقفة المستقيمة، النظر في العين، المشية الواثقة — كلها تبني هيبتك وتغيّر شعورك بنفسك. القوة تبدأ من الخارج وتنعكس للداخل.", practice:"اليوم: قف منتصباً، انظر في عيون من تحادثه، وامشِ بثبات وبطء.", mantra:"جسدك الواثق يصنع عقلاً واثقاً." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"لا تكن فريسة سهلة لاستفزازك", teach:"من يغضبك يملكك. الرجل القوي لا يُستدرَج للانفعال بكلمة أو إهانة. حين لا تتفاعل مع الاستفزاز، تنزع سلاح خصمك وتُظهر سيطرتك التامة على نفسك.", practice:"إن استفزّك أحد اليوم، توقّف، ابتسم، ولا تمنحه ردّ الفعل الذي يريد.", mantra:"من لا يستفزّ، لا يُهزَم." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"اعرف قيمتك ولا تساوم عليها", teach:"حين تعرف قدرك، لا تقبل أقل مما تستحق في عمل أو علاقة. من يجهل قيمته يقبل الفتات. الاحترام يبدأ من احترامك لنفسك أولاً — والناس تعاملك كما تعامل نفسك.", practice:"ارفض اليوم أمراً يقلّل من قدرك أو وقتك، بثقة وهدوء.", mantra:"من عرف قيمته رفع سعره." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"احفظ أسرارك وخططك", teach:"الرجل القوي لا يُعلن كل خطوة قبل أن يخطوها. الكلام عن الأهداف يُفرّغ طاقتها، والإفصاح عن خططك يمنح خصومك أفضلية. تكلّم بالنتائج لا بالنوايا.", practice:"اليوم، احتفظ بهدف أو خطة مهمة لنفسك ولا تخبر بها أحداً.", mantra:"دع نجاحك يتكلّم، لا لسانك." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"كن مرتاحاً في المواجهة", teach:"تجنّب الصراع دائماً يجعلك يُداس عليك. القوي لا يفتعل المعارك لكنه لا يهرب منها. واجه ما يجب بهدوء وحزم — فاحترامك يُبنى على استعدادك للوقوف عند الحق.", practice:"عالج اليوم موقفاً تتجنّبه بصراحة وهدوء بدل أن تبتلعه.", mantra:"السلام الحقيقي خلف المواجهة لا قبلها." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"اضبط انفعالاتك", teach:"العاطفة غير المنضبطة تقودك لقرارات تندم عليها. القوي يشعر بمشاعره لكنه لا يحكمه إياها. توقّف، سمِّ الشعور، ثم اختر ردّك بوعي بدل أن تنفجر.", practice:"حين تشتدّ مشاعرك اليوم، انتظر دقيقة وسمِّ ما تشعر به قبل أن تتصرّف.", mantra:"سيّد مشاعره سيّد مصيره." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"أنجز ما تبدأه", teach:"كثرة المشاريع الناقصة تنخر ثقتك. القوة تُبنى من إتمام ما تبدأ مهما صغُر. كل مهمة تُنهيها تثبت لعقلك أنك رجل يُعتمد عليه — وأقواها وعودك لنفسك.", practice:"أنهِ اليوم مهمة واحدة بدأتها وأجّلتها، حتى النهاية.", mantra:"الإتمام يبني الثقة، والتسويف يهدمها." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"اختر دائرتك بعناية", teach:"تصبح متوسط الخمسة الأقرب إليك. الضعفاء يجرّونك لأسفل، والأقوياء يرفعونك. احرس من تجالس كما تحرس مالك — فالبيئة تصنع الرجل أكثر مما يظن.", practice:"قلّل اليوم من وقتٍ مع شخص يستنزفك، وتواصل مع شخص يرفعك.", mantra:"أرني أصحابك أُرِك مستقبلك." },
  { pillar:"الشخصية القوية", icon:"🦁", color:"#0ea5e9", title:"لا تتذمّر ولا تشتكِ", teach:"الشكوى تجعلك ضحية وتطرد القوة منك. القوي يحوّل الشكوى إلى فعل: بدل أن يلعن الظلام يُشعل شمعة. التذمّر يريح لسانك ويُضعف هيبتك أمام نفسك والناس.", practice:"امضِ اليوم بلا شكوى واحدة — وكلّما هممت بها، حوّلها إلى خطوة عملية.", mantra:"الأقوياء يحلّون، والضعفاء يشتكون." },

  // ── الإيمان والروح ──
  { pillar:"الإيمان والروح", icon:"🕌", color:"#10b981", title:"ابدأ بالله وتوكّل", teach:"التوكّل أن تأخذ بالأسباب ثم تُسلّم النتيجة لله. القلق يأكل طاقتك، والتوكّل يحرّرها. افعل ما عليك بإتقان ثم ارتح، فالرزق مكتوب والنتيجة بيد من خلقك.", practice:"قبل أعمالك اليوم، قل: 'بسم الله، توكّلت على الله'، ثم اعمل بإخلاص واترك القلق.", mantra:"اعمل كأن كل شيء بيدك، وتوكّل كأن كل شيء بيد الله." },
  { pillar:"الإيمان والروح", icon:"🕌", color:"#10b981", title:"الصلاة موعد لا يُؤجَّل", teach:"الصلاة في وقتها تضبط إيقاع يومك وتعيد ترتيب أولوياتك. من يحفظ صلواته يحفظ نفسه من الانجراف. هي راحة لا عبء، ولقاءٌ يُعيدك إلى مركزك خمس مرات في اليوم.", practice:"اليوم: صلِّ كل صلاة في أول وقتها، ولا تدع العمل يؤخّرها.", mantra:"من ضبط صلاته ضبط حياته." },
  { pillar:"الإيمان والروح", icon:"🕌", color:"#10b981", title:"الذِّكر يطمئن القلب", teach:"القلب يصدأ كما يصدأ الحديد، وجلاؤه الذكر. أذكار الصباح والمساء حصنٌ لطاقتك ونفسك من القلق والوسواس. لسانٌ رطب بذكر الله قلبٌ ساكنٌ مطمئن.", practice:"خصّص ٥ دقائق لأذكار الصباح، ومثلها للمساء، بحضور قلب لا بمجرّد لسان.", mantra:"ألا بذكر الله تطمئن القلوب." },
  { pillar:"الإيمان والروح", icon:"🕌", color:"#10b981", title:"القناعة كنزٌ لا يفنى", teach:"الغنى غنى النفس لا كثرة المال. من قنع بما قُسم له ارتاح، ومن طمِع تعِب وإن ملك الدنيا. اشكر ما بين يديك تَرَهُ يكبر، واطمع فيما ليس لك يصغر ما تملك في عينيك.", practice:"اليوم: اعدُد ٣ نعمٍ تملكها ويتمنّاها غيرك، واشكر الله عليها بصدق.", mantra:"القناعة كنزٌ لا يفنى." },
  { pillar:"الإيمان والروح", icon:"🕌", color:"#10b981", title:"الرضا بالقدر راحة", teach:"ما أصابك لم يكن ليخطئك. الرضا بالقدر لا يعني التواكل، بل أن تبذل جهدك ثم تطمئن لحكمة الله فيما جرى. الساخط يتعذّب مرتين: بالمصيبة وبسخطه، والراضي يرتاح ويُؤجَر.", practice:"حين يخالف اليوم خطّتك، قل: 'قدّر الله وما شاء فعل'، وابحث عن الخير الخفيّ فيه.", mantra:"رضاك بقدر الله بابُ سكينتك." },

  // ── الصحة والطاقة ──
  { pillar:"الصحة والطاقة", icon:"💪", color:"#f97316", title:"النوم أساس كل شيء", teach:"قرارٌ واحدٌ سيئٌ بسبب قلّة النوم قد يكلّفك أكثر من ربح أسبوع. النوم ليس كسلاً بل صيانة لعقلك وجسدك. من ينام جيداً يقرّر بوضوح، ويتحكّم في انفعاله، ويرى الفرص التي يعميها التعب.", practice:"اليوم: حدّد موعد نومٍ ثابتاً، وأطفئ الشاشات قبله بنصف ساعة.", mantra:"نومك الليلة وضوحُ قراراتك غداً." },
  { pillar:"الصحة والطاقة", icon:"💪", color:"#f97316", title:"حرّك جسدك كل يوم", teach:"الجسد الساكن عقلٌ كسول. الحركة تضخّ الطاقة والمزاج والتركيز أكثر من أي قهوة. لا تحتاج ساعات في نادٍ — تكفيك حركة يومية ثابتة تُبقي دمك وطاقتك يجريان.", practice:"تحرّك اليوم ٢٠ دقيقة على الأقل: مشي، تمارين، أو حتى صعود الدرج.", mantra:"جسدٌ يتحرّك عقلٌ يتّقد." },
  { pillar:"الصحة والطاقة", icon:"💪", color:"#f97316", title:"طعامك وقودك", teach:"ما تأكله يصبح طاقتك ومزاجك وتركيزك. الأكل الثقيل والسكر يُغرقانك في الخمول، والأكل النظيف يمنحك صفاءً وثباتاً. لا تُطعم عقلك ما يُبطئه ثم تطلب منه أن يعمل بأفضل ما عنده.", practice:"اليوم: استبدل وجبة سريعة أو حلوى بخيارٍ صحيٍّ خفيف.", mantra:"أنت ما تأكل، فاختر وقوداً نظيفاً." },
  { pillar:"الصحة والطاقة", icon:"💪", color:"#f97316", title:"الماء أولاً", teach:"كثيرٌ من الإرهاق والصداع وضعف التركيز ليس إلا عطشاً مُقنّعاً. جسدك آلةٌ تحتاج ماءً لتعمل. ابدأ يومك بكوب ماء قبل القهوة، واجعل الماء رفيقك طوال النهار.", practice:"اشرب كوب ماء فور استيقاظك، وحافظ على الترطيب طوال اليوم.", mantra:"رطّب جسدك يصفُ ذهنك." },
  { pillar:"الصحة والطاقة", icon:"💪", color:"#f97316", title:"احمِ طاقتك", teach:"طاقتك محدودة كرصيدٍ في حساب، فلا تبدّدها على ما لا يستحق: جدالٌ عقيم، أخبارٌ تُقلق، أشخاصٌ يستنزفون. وجّه طاقتك لأهمّ شيء أوّلاً، واحرسها من اللصوص الصغار طوال اليوم.", practice:"حدّد اليوم مستنزِفاً واحداً لطاقتك (تطبيق، شخص، عادة) وقلّل تعرّضك له.", mantra:"احرس طاقتك كما تحرس مالك." },

  // ── إدارة الضغط ──
  { pillar:"إدارة الضغط", icon:"🧘", color:"#6366f1", title:"تنفّس قبل أن تتصرّف", teach:"حين يشتدّ الضغط، أول ما ينهار هو تنفّسك، ومعه يضيق تفكيرك. نَفَسٌ بطيءٌ عميقٌ يُطفئ إنذار جسدك ويعيد عقلك للتفكير الواضح. لا قرار جيّد يُتّخذ ونبضك يتسارع — اهدأ أولاً ثم قرّر.", practice:"عند أول موجة ضغطٍ اليوم: توقّف، خذ ٤ أنفاس بطيئة عميقة قبل أي كلمة أو فعل.", mantra:"اضبط نَفَسك تضبط قرارك." },
  { pillar:"إدارة الضغط", icon:"🧘", color:"#6366f1", title:"افصل ما تملك عمّا لا تملك", teach:"أغلب الضغط يأتي من محاولة التحكّم فيما هو خارج يدك: رأي الناس، حركة السوق، نتيجة لم تقع بعد. ركّز طاقتك كلها على ما تملك — أفعالك، استجابتك، خطوتك التالية — ودع الباقي. هنا تبدأ الراحة.", practice:"اكتب ما يضغطك اليوم في عمودين: 'أملكه' و'لا أملكه'، واعمل فقط على الأول.", mantra:"راحتك في حدود ما تملك." },
  { pillar:"إدارة الضغط", icon:"🧘", color:"#6366f1", title:"قسّم الجبل إلى خطوات", teach:"الضغط يكبر حين تنظر إلى الجبل كله دفعة واحدة. لا أحد يصعد جبلاً بقفزة، بل بخطوة تلو خطوة. اسأل: ما الخطوة الواحدة التالية فقط؟ افعلها، ثم التي بعدها. المهمة الضخمة تذوب حين تُقطّع.", practice:"خذ أكثر ما يُثقلك اليوم، واكتب أصغر خطوة تالية ممكنة، ونفّذها الآن.", mantra:"الجبل يُصعد خطوةً خطوة." },
  { pillar:"إدارة الضغط", icon:"🧘", color:"#6366f1", title:"الضغط إشارة لا عدو", teach:"الضغط ليس علامة ضعف، بل إشارة أنك أمام شيء يهمّك. أعِد تأطيره: 'أنا متحمّس' لا 'أنا خائف' — فالجسد واحد والتفسير يختلف. الأبطال لا يشعرون بضغط أقل، بل يقرؤونه كوقودٍ لا كتهديد.", practice:"حين تشعر بالتوتّر اليوم، قل لنفسك: 'هذه طاقة وتركيز، لا خطر'، واستخدمها.", mantra:"حوّل الضغط من تهديدٍ إلى وقود." },
  { pillar:"إدارة الضغط", icon:"🧘", color:"#6366f1", title:"أفرِغ الضغط لا تكتمه", teach:"الضغط المكتوم يتسرّب إلى جسدك وعلاقاتك وقراراتك. امنحه منفذاً صحياً: حركة، كتابة، حديث مع ثقة، أو دعاء. الرجل القوي لا يبتلع كل شيء حتى ينفجر، بل يُفرّغ بانتظام فيبقى صافياً متّزناً.", practice:"اليوم: فرّغ ضغطك بطريقة واحدة صحية — تمرين، أو دوّن ما يثقلك، أو تحدّث لمن تثق.", mantra:"ما تُفرّغه بوعيٍ لا ينفجر فيك فجأة." },

  // ── التوتر والقلق ──
  { pillar:"التوتر والقلق", icon:"🌊", color:"#06b6d4", title:"عِش لحظتك الآن", teach:"أغلب القلق سفرٌ إلى مستقبلٍ لم يأتِ بعد. عقلك يصنع أفلاماً مرعبة لأشياء قد لا تقع أبداً. أعِد نفسك إلى اللحظة: ما الذي يحدث الآن فعلاً؟ غالباً ستجد أنك بخير في هذه اللحظة بالذات.", practice:"حين يشرد عقلك للقلق اليوم، سمِّ ٥ أشياء تراها و٣ تسمعها لتعود إلى حاضرك.", mantra:"القلق سفرٌ إلى غدٍ لم يأتِ بعد." },
  { pillar:"التوتر والقلق", icon:"🌊", color:"#06b6d4", title:"فرِّغ همومك على الورق", teach:"الهمّ يدور في رأسك بلا نهاية لأنه حبيس. حين تكتبه يخرج من دائرة التفكير المفرغة إلى ورقةٍ يمكنك النظر فيها بهدوء. ما يبدو غولاً في الرأس يصغر حين تراه مكتوباً أمامك.", practice:"اكتب كل ما يقلقك اليوم في قائمة، ثم ضع بجانب كلٍّ خطوةً واحدة أو 'ليس بيدي'.", mantra:"ما يخرج من رأسك يفقد سطوته." },
  { pillar:"التوتر والقلق", icon:"🌊", color:"#06b6d4", title:"الأسوأ نادراً ما يقع", teach:"عقلك القلِق يبالغ في احتمال الكارثة وفي عجزك عن مواجهتها. اسأل بصدق: ما أسوأ ما قد يحدث؟ وما احتمال وقوعه؟ وكيف سأتصرّف لو وقع؟ ستكتشف أنك أقوى مما تظنّ وأن الكارثة أبعد مما تتخيّل.", practice:"خذ أكبر مخاوفك اليوم واسأل: ما احتمال وقوعه فعلاً؟ وما خطّتي لو وقع؟", mantra:"معظم ما نخافه لا يقع، وما يقع نتجاوزه." },
  { pillar:"التوتر والقلق", icon:"🌊", color:"#06b6d4", title:"حدِّد موعداً للقلق", teach:"القلق المنتشر طوال اليوم يستنزفك. بدل أن تقاومه (فيزداد)، واعِده موعداً: 'سأقلق ١٥ دقيقة مساءً، لا الآن'. غالباً يخفّ حين يأتي موعده. أنت تحجز للقلق ركناً صغيراً بدل أن يحتلّ يومك كله.", practice:"حين يداهمك القلق اليوم، قل: 'موعدنا المساء'، وارجع لعملك. وفي موعده ستجده هان.", mantra:"لا تدع القلق يحتلّ يومك كله." },
  { pillar:"التوتر والقلق", icon:"🌊", color:"#06b6d4", title:"حرّك جسدك واذكر ربّك", teach:"التوتر طاقة محبوسة في الجسد، والحركة تفرّغها أسرع من أي تفكير. مشيٌ قصير، أو وضوءٌ وصلاة، أو ذكرٌ بحضور قلب — كلها تُنزل منسوب التوتر فوراً. لا تبقَ جالساً تجترّ القلق؛ قُم وحرّك جسدك واسكُب قلبك لمن يسمعك.", practice:"عند اشتداد التوتّر اليوم: قُم، امشِ قليلاً، توضّأ أو اذكر الله بتركيز لخمس دقائق.", mantra:"حرّك جسدك واطمئنّ بذكر ربّك." },

  // ── سيكولوجيا التداول ──
  { pillar:"سيكولوجيا التداول", icon:"🧠", color:"#8b5cf6", title:"اقتل الخوف من فوات الفرصة (FOMO)", teach:"السهم يطير وأنت خارجه، فيصرخ عقلك: 'الحق به قبل أن يفوتك!'. هذا الصوت أفلس متداولين أكثر من أي خبر. السوق يصنع فرصاً كل يوم، ومن يطارد القمم يشتري حماس غيره ويحمل خسارتهم. الفرصة الفائتة لا تكلّفك شيئاً، أما الدخول المتأخّر بانفعال فيكلّفك رأس مالك.", practice:"اليوم: إن وجدت نفسك تطارد سهماً ارتفع بقوة بلا إشارة من خطتك، لا تدخل. اكتب اسمه وراقبه فقط.", mantra:"الفرصة الفائتة أرخص من الدخول المنفعل." },
  { pillar:"سيكولوجيا التداول", icon:"🧠", color:"#8b5cf6", title:"لا تنتقم من السوق", teach:"بعد خسارة موجعة يولد شيطان 'تداول الانتقام': تكبّر المركز وتدخل بلا خطة لتسترجع ما خسرت بسرعة. لكن السوق لا يعرفك ولا يدين لك بشيء. الانتقام يحوّل خسارة صغيرة إلى كارثة. الخسارة جزء من اللعبة، والمحترف يتقبّلها ويلتزم حجمه الطبيعي، أما الهاوي فيضاعف ليثأر فيُدفن.", practice:"بعد أي صفقة خاسرة اليوم، توقّف ٢٠ دقيقة قبل الصفقة التالية، وادخل بنفس حجم المخاطرة لا أكبر.", mantra:"السوق لا يدين لك بشيء — لا تثأر منه." },
  { pillar:"سيكولوجيا التداول", icon:"🧠", color:"#8b5cf6", title:"اقطع الخاسر بلا تردّد", teach:"أصعب شيء نفسياً أن تعترف أنك مخطئ وتبيع بخسارة. فيتشبّث عقلك بالأمل: 'سيرتدّ'. هذا الأمل يحوّل خسارة صغيرة منضبطة إلى ثقب يبتلع حسابك. وقف الخسارة ليس هزيمة بل قسط تأمين على بقائك. المحترف يخسر صغيراً كثيراً، لكنه لا يخسر كبيراً أبداً.", practice:"راجع مراكزك المفتوحة اليوم — أي مركز كسر وقف خسارته، أغلقه فوراً بلا تفاوض مع نفسك.", mantra:"الخسارة الصغيرة قسط بقائك، فلا تؤجّلها." },
  { pillar:"سيكولوجيا التداول", icon:"🧠", color:"#8b5cf6", title:"دع الرابح يجري", teach:"الخوف يجعلك تبيع الرابح مبكراً لتأمين مكسب صغير، بينما تترك الخاسر يكبر. هذا عكس الثراء تماماً. القلّة من الصفقات الكبيرة الرابحة هي ما يصنع حسابك كله. حين تكون على ربح والاتجاه سليم، لا تقتل الصفقة خوفاً — حرّك وقفك للأعلى ودع السوق يخرجك، لا انفعالك.", practice:"في أي مركز رابح اليوم، بدل البيع المبكر، ارفع وقف الخسارة تحت السعر ودع الصفقة تتنفّس.", mantra:"اقطع الخاسر بسرعة، واترك الرابح يجري." },
  { pillar:"سيكولوجيا التداول", icon:"🧠", color:"#8b5cf6", title:"احذر الغرور بعد سلسلة أرباح", teach:"أخطر لحظة ليست بعد الخسارة بل بعد سلسلة انتصارات. النجاح يولّد غروراً: تكبّر المراكز، تتجاهل القواعد، تظنّ أنك هزمت السوق. هنا بالضبط تأتي الضربة التي تمحو أرباح أسابيع. السوق يتواضع كل واثق زائد. عامل صفقتك العاشرة الرابحة بنفس انضباط الأولى.", practice:"بعد يومٍ رابح اليوم، لا تزد حجم مخاطرتك في الصفقة التالية. التزم بنفس النسبة تماماً.", mantra:"بعد الربح تواضع، فالغرور بداية الخسارة." },
  { pillar:"سيكولوجيا التداول", icon:"🧠", color:"#8b5cf6", title:"العملية أهم من النتيجة", teach:"قد تتّبع خطتك تماماً وتخسر، وقد تكسر كل قاعدة وتربح بالحظ. لو حكمت على نفسك بالنتيجة وحدها، كافأت العشوائية وعاقبت الانضباط. احكم على نفسك بجودة قراراتك لا بنتيجة صفقة واحدة. النتائج تتقلّب، لكن العملية الجيدة المكرّرة تربح على المدى الطويل حتماً.", practice:"بعد إغلاق أي صفقة اليوم، اسأل: 'هل اتّبعت خطتي؟' لا 'هل ربحت؟' — وقيّم نفسك على الالتزام.", mantra:"التزم بالعملية، والنتائج تأتي وحدها." },
  { pillar:"سيكولوجيا التداول", icon:"🧠", color:"#8b5cf6", title:"تقبّل عدم اليقين", teach:"كل صفقة احتمال لا يقين. حتى أفضل إشارة قد تفشل، وأسوأ إشارة قد تنجح — وهذا طبيعي. حين تطلب اليقين من سوق احتمالي، تتجمّد أو تنفعل عند كل خسارة. المحترف يفكّر بالاحتمالات: 'هذه صفقة من مئة، نتيجتها الفردية لا تهمّ، المهم أن الحدّ كله رابح'. هكذا تهدأ نفسك.", practice:"قبل دخولك اليوم، قل: 'هذه مجرّد احتمال واحد في سلسلة طويلة'، ولا تربط قيمتك بنتيجتها.", mantra:"فكّر بالاحتمالات لا باليقين." },
  { pillar:"سيكولوجيا التداول", icon:"🧠", color:"#8b5cf6", title:"خاطر بما تقدر على خسارته فقط", teach:"حين تخاطر بمال تحتاجه أو بحجم أكبر من احتمالك النفسي، يتحوّل كل تذبذب إلى رعب، ويقودك الخوف لقرارات حمقاء: بيع في القاع، خروج مبكر، يدٌ ترتجف. الحجم الصحيح هو الذي تنام معه مرتاحاً وتفكّر معه بوضوح. صغّر مركزك حتى يهدأ قلبك — راحتك النفسية جزء من استراتيجيتك.", practice:"اليوم: تأكّد أن خسارة أي صفقة لن تتجاوز ١٪ من حسابك. إن كنت متوتراً، صغّر الحجم حتى تهدأ.", mantra:"الحجم الذي يُفقدك نومك أكبر من اللازم." },
  { pillar:"سيكولوجيا التداول", icon:"🧠", color:"#8b5cf6", title:"اعرف متى تبتعد عن الشاشة", teach:"ليست كل الأيام أيامك. حين تتوالى الخسائر أو تشعر بغضب أو إرهاق أو ملل، يصبح عقلك عدوّك، وكل صفقة محاولة لإصلاح مزاجك لا لقراءة السوق. أعظم مهارة أحياناً ألا تتداول. أغلق المنصّة، امشِ، صلِّ، عُد غداً بعقل صافٍ. المال سيبقى في السوق، أما رأس مالك فلا يعود إن بدّدته بانفعال.", practice:"اليوم: إن خسرت صفقتين متتاليتين أو شعرت بانفعال، أغلق المنصّة لبقية الجلسة بلا ذنب.", mantra:"عدم التداول قرارٌ رابح أيضاً." },

  // ── التحليل النفسي ──
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"اقرأ الدافع لا الكلمة", teach:"الناس نادراً ما يقولون سبب تصرّفهم الحقيقي. خلف كل سلوك حاجة: أمان، تقدير، سيطرة، أو انتماء. حين تسأل 'ما الذي يحتاجه هذا الشخص فعلاً؟' بدل 'لماذا يزعجني؟' تفهمه وتتعامل معه بحكمة بدل أن تتصادم معه.", practice:"في أصعب موقف اليوم، توقّف واسأل نفسك: ما الحاجة الدفينة وراء تصرّف هذا الشخص؟", mantra:"افهم الحاجة تفهم الإنسان." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"الإسقاط: ما يزعجك فيهم قد يكون فيك", teach:"كثيراً ما ننتقد في الآخرين ما نرفض رؤيته في أنفسنا. الذي يثيرك بشدّة في غيرك مرآة لجرح أو خوف داخلك. حين تلاحظ ردّ فعل قوياً، اسأل: هل هذا عنه أم عنّي؟ هكذا تنضج وتهدأ.", practice:"لاحظ اليوم أكثر ما أغضبك في أحدهم، واسأل بصدق: هل أحمل شيئاً من هذا أنا؟", mantra:"ما يستفزّك يكشفك أكثر مما يكشفه." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"ميّز الثابت من العابر", teach:"لا تحكم على شخصية أحد من لحظة غضب أو يوم سيّئ. السلوك العابر مزاج، والسلوك المتكرّر طبع. راقب الأنماط لا اللقطات: كيف يتصرّف تحت الضغط، وكيف يعامل من لا ينفعه — هناك تظهر حقيقته.", practice:"بدل الحكم السريع اليوم، راقب نمط تصرّف شخص عبر مواقف متعدّدة قبل أن تستنتج.", mantra:"الطبع يتكرّر، والمزاج يعبر." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"أنصت لما لا يُقال", teach:"الرسالة الحقيقية كثيراً ما تكون في الصمت، في التهرّب من سؤال، في تغيير الموضوع، أو في حماس مبالغ فيه. ما يتجنّبه الناس يخبرك أكثر مما يقولونه. أصغِ للفجوات لا للكلمات وحدها.", practice:"في حديث اليوم، انتبه لما يتجنّب محدّثك ذكره — وستفهم ما يشغله حقاً.", mantra:"أبلغ الكلام أحياناً هو المسكوت عنه." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"لا تحلّل لتتلاعب بل لتفهم وترحم", teach:"قراءة النفوس قوة، والقوة أمانة. استخدم فهمك للناس لتعينهم وتتجنّب الأذى، لا لتستغلّ ضعفهم. من حلّل الناس ليتلاعب بهم فقد قلبه، ومن حلّلهم ليرحمهم ويهديهم نَبُل وكُسب الثقة.", practice:"وظّف فهمك لشخص اليوم في مساعدته أو تهدئته، لا في كسب جولة عليه.", mantra:"الفهم رحمة لا سلاح." },

  // ── لغة الجسد ──
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"الجسد يصدق حين يكذب اللسان", teach:"الكلمات تُجمَّل، أما الجسد فيتسرّب منه الصدق: تجنّب النظر، خطوة للخلف، ذراعان مطويّتان، ابتسامة لا تصل العينين. حين تتعارض الكلمة مع الإشارة، صدّق الجسد. لكن لا تبنِ حكماً على إشارة واحدة، بل على تجمّعها مع السياق.", practice:"في حوار اليوم، لاحظ تطابق كلمات محدّثك مع جسده — وأين يتسرّب التردّد.", mantra:"اللسان يُجمّل، والجسد يبوح." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"اقرأ العنقود لا الإشارة الواحدة", teach:"ذراع مطويّة قد تعني البرد لا الانغلاق، ولمس الأنف قد يكون حكّة لا كذباً. الإشارة الواحدة لا تكفي. ابحث عن 'عنقود': ثلاث إشارات متّسقة في سياق واحد. حينها فقط يصبح القراءة موثوقة. التسرّع في التأويل أكبر خطأ.", practice:"اليوم: لا تستنتج من حركة واحدة؛ انتظر تجمّع إشارات قبل أن تقرأ الموقف.", mantra:"إشارة واحدة صدفة، وثلاث رسالة." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"خط الأساس أولاً", teach:"لتعرف متى يتغيّر شخص، اعرف حالته الطبيعية أولاً. بعض الناس يتجنّبون النظر بطبعهم، وبعضهم يتحرّكون كثيراً دائماً. راقب 'خط الأساس' في الراحة، ثم انتبه للانحراف عنه — فالتغيّر المفاجئ هو الإشارة، لا السلوك بذاته.", practice:"لاحظ اليوم الحالة الطبيعية لشخص تعرفه، ثم انتبه متى تتغيّر فجأة — هناك المعنى.", mantra:"المعنى في التغيّر، لا في الوضع الثابت." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"القدمان تشيران إلى الرغبة", teach:"أصدق جزء في الجسد هو الأبعد عن وعينا: القدمان. إن اتّجهت قدما محدّثك نحو الباب فعقله يريد المغادرة وإن طالت ابتسامته. وإن اتّجهتا نحوك فهو مهتمّ. راقب اتجاه الأقدام والصدر لتعرف أين يريد الشخص أن يكون حقاً.", practice:"في لقاء اليوم، انظر إلى اتجاه أقدام من تحادث — هل هي نحوك أم نحو المخرج؟", mantra:"القدمان تكشفان ما يخفيه الوجه." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"اضبط جسدك تضبط حضورك", teach:"كما تقرأ الناس، هم يقرؤونك. الوقفة المنتصبة، الكتفان المسترخيان، التنفّس البطيء، النظر الهادئ الثابت — كلها تبثّ ثقة وطمأنينة تَعدي من حولك. غيّر جسدك تتغيّر حالتك الداخلية ونظرة الناس إليك معاً.", practice:"قبل موقف مهمّ اليوم: قف منتصباً، أرخِ كتفيك، تنفّس بعمق، وادخل بثبات.", mantra:"جسد واثق يصنع حضوراً مهيباً." },

  // ── التحليل النفسي — تعمّق ──
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"آليات الدفاع النفسي", teach:"حين يهدّد الواقع صورة الإنسان عن نفسه، يلجأ عقله لاوعيٍّ إلى حِيَل تحميه: الإنكار ('لا مشكلة عندي')، التبرير ('فعلتُها لأنّ…')، والإسقاط (يرمي عيبه على غيره). من يعرف هذه الآليات لا ينخدع بظاهر الكلام، ويرى الخوف الكامن خلف الدفاع. وأهمّها أن تراقبها في نفسك أولاً.", practice:"اليوم: التقط مرّة واحدة برّرت فيها خطأك بدل الاعتراف به، وسمِّ الآلية بصدق.", mantra:"خلف كل دفاعٍ عنيد خوفٌ يطلب الأمان." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"حالات الأنا الثلاث", teach:"في كل تفاعل نتكلّم من إحدى ثلاث: 'الوالد' (آمر/ناقد)، 'الطفل' (منفعل/متمرّد)، أو 'الراشد' (هادئ يحلّل الواقع). أكثر الصدامات حين يردّ طفلٌ على والد. حين تتعمّد البقاء في 'الراشد' — صوت هادئ، حقائق، لا انفعال — تجبر الآخر على الصعود إليك بدل أن تنزل إليه.", practice:"في أول توتّر اليوم، اسأل: من يتكلّم فيّ الآن؟ واختر أن تردّ من 'الراشد'.", mantra:"تكلّم كراشدٍ يردّ عليك راشد." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"اخرج من مثلث الدراما", teach:"كثير من العلاقات المتعِبة تدور في مثلث: ضحية تشكو، ومنقِذ يتدخّل، ومُضطهِد يلوم — والأدوار تتبادل بلا نهاية. لا تنجرّ إليه. بدل أن 'تنقذ' علِّم، وبدل أن 'تتّهم' اطلب بوضوح، وبدل أن تكون 'ضحية' تحمّل مسؤوليتك. الخروج من المثلث يحرّرك ويحرّرهم.", practice:"لاحظ اليوم متى تنجرّ لدور المنقِذ أو الضحية، واخرج منه بسؤال عمليّ: ما الخطوة التالية؟", mantra:"لا ضحية ولا منقِذ — بل راشدٌ مسؤول." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"الجرح الأساسي يحرّك السلوك", teach:"وراء أغلب ردود الفعل المبالغ فيها جرحٌ قديم: خوف الهجر، أو الرفض، أو ألا يكون 'كافياً'. حين ينفجر أحدهم لسبب تافه، فالموقف لمس جرحه لا أنت. أن ترى الطفل المجروح خلف الغاضب يمنحك صبراً ورحمة بدل التصعيد.", practice:"حين يبالغ أحدهم في الغضب اليوم، اسأل بصمت: أيّ جرحٍ قديم لمسه هذا الموقف؟", mantra:"الانفجار الكبير جرحٌ صغير قديم." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"احذر التلاعب العاطفي", teach:"بعض الناس يديرونك بالشعور: التذنيب ('بعد كل ما فعلتُ لك')، والضحية الدائمة، والتشكيك في إدراكك (الغازلايتنغ). العلامة أنك تخرج من كل لقاء معهم محمّلاً بالذنب أو الحيرة. لا تجادل المتلاعب، بل احفظ حدودك بهدوء وثقة بما رأيته وعشته.", practice:"لاحظ اليوم بعد كل تفاعل: هل خرجتُ مرتاحاً أم مثقلاً بذنبٍ مصطنع؟ وسمِّ المصدر.", mantra:"من يزرع فيك الذنب دائماً يطلب التحكّم لا الحب." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"عقلك ليس محايداً", teach:"دماغك يختصر الواقع بانحيازات: تبحث عمّا يؤكّد رأيك (انحياز التأكيد)، وتثق بأول انطباع (الترسيخ)، وتلوم الناس على أخطائهم وتعذر نفسك بالظروف. الوعي بهذه الفخاخ يجعل أحكامك على الناس أعدل، وقراراتك أصفى. تواضع أمام عقلك قبل أن تثق به كلّياً.", practice:"اليوم: راجع حكماً سريعاً أصدرته على أحد، واسأل: ما الدليل المضادّ الذي تجاهلتُه؟", mantra:"أول التواضع أن تشكّ في يقين عقلك." },

  // ── لغة الجسد — تعمّق ──
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"التعابير الدقيقة (الميكرو)", teach:"المشاعر الحقيقية تومض على الوجه في أجزاء من الثانية قبل أن يخفيها صاحبها — تعبير 'ميكرو'. سبعة مشاعر عالمية لها بصمة ثابتة: الفرح، الحزن، الغضب، الخوف، الاشمئزاز، الدهشة، الاحتقار. حين تلمح وميضاً يخالف الكلمات، فتلك هي الحقيقة قبل أن تُغلَّف.", practice:"في حديث اليوم، راقب أول نصف ثانية من ردّ فعل وجه محدّثك قبل أن 'يرتّب' تعبيره.", mantra:"أصدق تعبيرٍ هو أوّله وأسرعه." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"إشارات التهدئة الذاتية", teach:"حين يتوتّر الإنسان يهدّئ نفسه لاشعورياً: يلمس رقبته، يفرك يديه، يعبث بساعته، يلمس شفتيه. ارتفاع هذه الإشارات بعد سؤالٍ معيّن يكشف أن السؤال لمس منطقة حسّاسة. لا تتّهم بالكذب — بل اعلم أنّ هنا توتراً يستحقّ مزيد فهم.", practice:"اليوم: انتبه متى تكثر يدا محدّثك من لمس وجهه أو رقبته — وأيّ موضوع أثار ذلك.", mantra:"اليد تهدّئ الجسد حين يقلق القلب." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"المسافة تتكلّم", teach:"لكل إنسان مناطق: حميمة (نصف متر) لا يدخلها إلا المقرّبون، وشخصية (متر)، واجتماعية (أبعد). من يقترب أكثر من اللازم يضغط أو يستحوذ، ومن يتراجع يضع حاجزاً. راقب كيف يضبط الناس المسافة معك ومع غيرك — فهي تكشف الراحة والسلطة والرغبة.", practice:"لاحظ اليوم كيف يقترب منك الناس أو يبتعدون — ومتى شعرت أنت بالحاجة لمسافة.", mantra:"المسافة بين جسدين تروي علاقتهما." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"العينان: الاتجاه والاتّساع", teach:"حدقة العين تتّسع مع الاهتمام والانجذاب، وتضيق مع الرفض. واتّجاه النظر يكشف: نظرة طويلة قد تكون تحدّياً أو إعجاباً حسب السياق، وكثرة الرمش علامة توتّر. لكن احذر التأويل الجامد — اقرأ العين ضمن عنقود وسياق، لا وحدها.", practice:"في لقاء اليوم، لاحظ متى تتّسع حدقة محدّثك (اهتمام) ومتى يكثر رمشه (توتّر).", mantra:"العين نافذةٌ تتّسع للرغبة وتضيق للرفض." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"المحاكاة تبني الألفة", teach:"حين ينسجم شخصان يتطابق جسداهما لاشعورياً: نفس الوضعية، إيقاع الكلام، الإيماءات. هذه 'المرآة' علامة ألفة، ويمكنك استخدامها بلطف: حاكِ إيقاع محدّثك وطاقته بهدوء فيشعر بالأمان والقرب. لكن بلا افتعال — التقليد الفجّ يُنفّر.", practice:"اليوم: طابق بهدوء نبرة وإيقاع شخص تريد تقريبه، وراقب كيف تلين العلاقة.", mantra:"الأجساد المنسجمة قلوبٌ متقاربة." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"اقرأ الموقف لا الإنسان فقط", teach:"لغة الجسد ليست كشف كذب سحرياً؛ هي قراءة راحةٍ أو توتّر في لحظة. الإشارة نفسها تختلف معناها بالثقافة والسياق والحالة الصحية. القارئ الحكيم يجمع: خط الأساس + عنقود إشارات + سياق الموقف، ثم يضع فرضية لا حكماً قاطعاً. التواضع يقيك أخطاء التأويل.", practice:"اليوم: حين تقرأ موقفاً، صُغ استنتاجك كاحتمال ('يبدو متوتراً') لا كحقيقة ('إنه يكذب').", mantra:"اقرأ بثقةٍ، واحكم بتواضع." },

  // ── التحليل النفسي — تطبيق متقدّم ──
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"أنماط التعلّق الثلاثة", teach:"طريقة ارتباط الإنسان تشكّلت في طفولته وتظهر في كل علاقة: الآمن (يثق ويقترب بلا خوف)، القلِق (يخاف الهجر فيتشبّث ويطالب)، والمتجنّب (يخاف الاقتراب فيهرب عند الالتزام). حين تعرف نمط من أمامك، تفهم لماذا يتشبّث أو ينسحب، وتتوقّف عن أخذه على محمل شخصيّ. واعرف نمطك أنت أولاً.", deep:"نمط التعلّق هو 'برنامج' تعلّمه الطفل عن العلاقات من طريقة تعامل من رعاه، ويبقى يعمل في الكبر:\n• الآمن: نشأ على رعايةٍ ثابتة، فيثق بالقرب ولا يخاف الاستقلال. يطلب حاجته بوضوح ويتقبّل المسافة.\n• القلِق: نشأ على رعايةٍ متقلّبة (حاضرة أحياناً، غائبة أحياناً)، فصار يراقب أيّ إشارة هجر، يتشبّث، يطلب طمأنةً متكرّرة، ويبالغ في ردّ الفعل عند الفتور.\n• المتجنّب: نشأ على رعايةٍ باردة أو مقتحِمة، فتعلّم أن الاعتماد خطر؛ يبدو مستقلّاً قويّاً لكنه ينسحب عند الالتزام أو القرب العاطفيّ.\nالفائدة العملية: حين يتشبّث القلِق لا تأخذه ضعفاً بل خوفاً، وطمئنه. وحين ينسحب المتجنّب لا تطارده بل امنحه مساحةً آمنة. والأهمّ: اعرف نمطك أنت، فأنماطنا غالباً ما تتجاذب بشكلٍ مؤلم (القلِق يطارد، والمتجنّب يهرب). والوعي أول خطوةٍ نحو 'الأمان المكتسَب'.", practice:"تأمّل اليوم: هل تميل للتشبّث عند الخوف أم للانسحاب؟ ولاحظ نمط أقرب الناس إليك.", mantra:"كل تشبّثٍ أو هروبٍ جذره في طفولةٍ بعيدة." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"التحقّق قبل الحلّ", teach:"حين يأتيك إنسان بألمه، أول حاجته أن يُسمَع ويُفهَم، لا أن يُصلَح. القفز إلى النصيحة يشعره أنك تتجاوز مشاعره. قل أولاً: 'أفهم لماذا تشعر بهذا، له معنى'. هذا 'التحقّق' يفتح القلب ويهدّئ الجهاز العصبي، وبعده فقط يصبح العقل مستعدّاً للحلّ.", deep:"'التحقّق' (Validation) يعني أن تعترف بأن لمشاعر الآخر معنىً ومنطقاً من زاويته — لا أن توافق على رأيه. ولماذا يسبق الحلّ؟\n• عصبياً: حين يكون الإنسان منفعلاً يكون 'العقل العاطفيّ' مسيطراً و'العقل المنطقيّ' معطّلاً. التحقّق يهدّئ الجهاز العصبيّ فيعود التفكير المنطقيّ للعمل؛ فالنصيحة قبل التهدئة تسقط على أذنٍ مغلقة.\n• نفسياً: القفز للحلّ يُسمَع كرسالة خفيّة: 'مشكلتك تافهة، إليك الحلّ' أو 'مشاعرك خاطئة' — فيتراجع الآخر ويدافع بدل أن ينفتح.\nصيغ التحقّق: 'من الطبيعيّ أن تشعر بهذا'، 'أنا أفهم لماذا أزعجك ذلك'، 'لو كنتُ مكانك لشعرتُ بالمثل'. ثم اصمت لحظة. وبعد أن يهدأ ويشعر أنه فُهِم، اسأله: 'هل تحبّ أن نفكّر في حلّ معاً؟' — فلا تفرض حلّك بل تُدعى إليه.", practice:"اليوم: قبل أن تنصح أحداً، تحقّق من شعوره بجملة واحدة صادقة، ثم اصمت لحظة.", mantra:"القلب يُسمَع أولاً، ثم يُرشَد." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"الصخرة الرمادية أمام المتلاعب", teach:"المتلاعب والمستفِزّ يتغذّى على ردّ فعلك العاطفي. إن حرمته الوقود انطفأ. تقنية 'الصخرة الرمادية': ردود قصيرة محايدة، نبرة هادئة، بلا تفاصيل تثيره ولا انفعال يغذّيه. لا تشرح ولا تدافع ولا تصارع — كن مملاًّ كصخرة. حين لا يجد فيك ما يحرّكه، يبحث عن فريسة أخرى.", deep:"المتلاعب (خاصّةً النرجسيّ أو مثير المشاكل) يبحث عن ردّ فعلٍ عاطفيّ — غضبك، دموعك، دفاعك — لأنه يثبت له أنه يملك زرّ التحكّم فيك. 'الصخرة الرمادية' تجفّف هذا الوقود:\n• ردودٌ قصيرة محايدة: 'حسناً'، 'ربّما'، 'قد يكون'. بلا تفاصيل يتعلّق بها.\n• نبرةٌ ثابتة، وجهٌ هادئ، بلا انفعالٍ ظاهر — لا غضب ولا اعتذار.\n• لا تشرح ولا تبرّر ولا تجادل؛ التبرير دعوةٌ لجولةٍ جديدة.\n• لا تشاركه ما يهمّك (لئلّا يصير سلاحاً ضدّك لاحقاً).\nمتى تستخدمها؟ مع من ثبت أنه يتلاعب أو يستنزف، لا مع كل خلاف. وحذارِ: مع المقرّبين الأسوياء، الصخرة الرمادية تؤذي العلاقة لأنها بَرَدٌ وانسحاب؛ هناك المطلوب حوارٌ صريح لا تجاهل. الأداة للمتلاعب فقط، والحدّ الأقصى منها أن تبتعد عمّن لا يتغيّر.", practice:"إن استفزّك أحدٌ اليوم، ردّ بجملة قصيرة محايدة بلا انفعال، ولا تمنحه التفاصيل.", mantra:"احرم النار وقودها تنطفئ." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"أعِد صياغة فكرتك", teach:"ليست الأحداث ما يؤلمك بل تفسيرك لها. 'تجاهلني' قد تعني 'يكرهني' أو 'كان مشغولاً'. عقلك يختار التفسير الأسوأ تلقائياً. التقط الفكرة المؤلمة، واسأل: ما تفسير آخر محتمل وأرحم وأقرب للواقع؟ هذه 'إعادة الصياغة المعرفية' تغيّر شعورك دون أن يتغيّر الحدث.", deep:"هذا جوهر العلاج المعرفيّ السلوكيّ (CBT): بين الحدث والشعور تقف 'فكرةٌ تلقائية' غالباً ما نمرّ عليها دون وعي، وهي التي تصنع الألم لا الحدث نفسه. الدليل أن نفس الموقف يؤلم شخصاً ولا يؤلم آخر — لاختلاف التفسير.\nخطوات إعادة الصياغة عملياً:\n١) التقط الفكرة: ما الذي قلتُه لنفسي بالضبط؟ ('لم يردّ على رسالتي = لا يحترمني').\n٢) افحص الدليل: ما الذي يؤيّد هذا التفسير؟ وما الذي يناقضه؟ (ربّما مشغول، ربّما لم يرَها).\n٣) ابحث عن تفسيرٍ بديل أرحم وأقرب للواقع، وليس مجرّد 'تفاؤل' كاذب.\n٤) لاحظ التشوّهات الشائعة: التعميم ('دائماً'، 'أبداً')، قراءة الأفكار، التضخيم، التفكير الأبيض/الأسود.\nالمهارة لا تنكر الواقع، بل تحرّرك من تفسيرٍ واحدٍ متشائمٍ تتبنّاه عقلك تلقائياً. مع التكرار تصبح أهدأ تلقائياً.", practice:"اليوم: خذ فكرة أزعجتك، واكتب لها تفسيرين بديلين أكثر رحمة وواقعية.", mantra:"غيّر التفسير يتغيّر الألم." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"افهم أثر الصدمة على السلوك", teach:"من عاش صدمة قد يردّ على مواقف عاديّة بردّ فعل ضخم: تجمّد، أو هجوم، أو هروب. ليس ضعفاً ولا تمثيلاً، بل جهازٌ عصبيّ تعلّم أن يحمي صاحبه. حين ترى ردّ فعل لا يتناسب مع الموقف، اسأل بلطف لا بحكم: 'ما الذي مرّ به هذا الإنسان؟' الرحمة تبدأ حين نفهم أن خلف القسوة ألماً.", deep:"الصدمة تُعيد ضبط 'نظام الإنذار' في الدماغ (اللوزة العصبية) ليصبح شديد الحساسية. فموقفٌ عاديّ قد يُقرَأ كخطرٍ قديم، فينطلق ردّ فعلٍ بدائيّ خارج إرادة صاحبه:\n• القتال (Fight): غضبٌ مفاجئ، هجومٌ دفاعيّ.\n• الهروب (Flight): انسحاب، تجنّب، تغيير الموضوع، قلق.\n• التجمّد (Freeze): شرود، صمت، 'انفصال' عن اللحظة.\n• الاسترضاء (Fawn): إرضاءٌ مفرط وإلغاءٌ للذات لتفادي الصراع.\nالمفتاح: حين يكون الإنسان في هذه الحالة لا يكون 'عقله المنطقيّ' متاحاً — فالجدال أو اللوم يزيد الإنذار اشتعالاً. الأنفع: الأمان (نبرةٌ هادئة، مسافةٌ محترمة، بلا تهديد)، فينطفئ الإنذار ويعود العقل.\nتنبيهٌ مهمّ: هذا فهمٌ يورّث الرحمة، لا تشخيصٌ نفسيّ ولا تبريرٌ للأذى. الفهم لا يلغي المسؤولية ولا حماية نفسك من سلوكٍ مؤذٍ. أنت تفسّر لتتعامل بحكمة، والعلاج الحقيقيّ شأن المختصّين.", practice:"حين يبالغ أحدهم في ردّة فعله اليوم، بدّل 'ما خطبه؟' بـ 'ما الذي جرحه يوماً؟'.", mantra:"خلف ردّ الفعل المبالغ تاريخٌ لا تعرفه." },
  { pillar:"التحليل النفسي", icon:"🔍", color:"#9333ea", title:"الإصغاء العميق فنّ", teach:"أكثر الناس يسمعون ليردّوا لا ليفهموا. الإصغاء العميق: عينان حاضرتان، صمتٌ بلا مقاطعة، وأسئلة تفتح لا تغلق ('وماذا حدث بعدها؟')، ثم تلخيص ما سمعت بكلماتك للتأكّد. حين يشعر الإنسان أنه فُهِم حقاً، يمنحك ثقةً وقلباً لا يشتريهما مال. هذه أندر مهارة وأقواها.", deep:"الإصغاء العميق (Active Listening) أرقى من 'الإنصات الصامت'؛ هو حضورٌ كامل يجعل الآخر يشعر أنه مرئيّ ومفهوم. أركانه:\n• الحضور الكامل: أبعد الهاتف، واجه الشخص، تواصلٌ بصريّ هادئ. الإلهاء يُسمَع كرسالة 'لستَ مهمّاً'.\n• الصمت بلا مقاطعة: لا تكمل جمله، ولا تجهّز ردّك بينما يتكلّم. اترك فجواتٍ صغيرة؛ غالباً يقول الناس أعمق ما عندهم في الصمت الذي يليه.\n• الأسئلة المفتوحة: 'كيف شعرت؟'، 'وماذا حدث بعدها؟' — تفتح، بعكس 'ألم يكن خطأك؟' التي تغلق وتحاكم.\n• الانعكاس والتلخيص: أعِد ما فهمت بكلماتك ('إذن أنت منزعجٌ لأن…') — فهذا يثبت أنك سمعت، ويصحّح أيّ سوء فهم، ويعمّق ثقته.\n• كبح غريزة الإصلاح: مقاومة الرغبة في القفز للحلّ هي أصعب جزء وأهمّه.\nأثرها هائل: من يشعر أنه فُهِم حقاً يهدأ، ينفتح، ويمنحك ولاءً لا يُشترى. وهي أندر مهارةٍ لأن الجميع يريد أن يتكلّم، وقليلٌ من يُحسن أن يُصغي.", practice:"في حوار اليوم: لا تقاطع، اطرح سؤالاً مفتوحاً واحداً، ولخّص ما فهمت قبل أن تردّ.", mantra:"من أصغى بعمقٍ مَلَك القلوب." },

  // ── لغة الجسد — تطبيق متقدّم ──
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"المصافحة تكشف الكثير", teach:"المصافحة أوّل رسالة جسدية: القبضة المتوازنة الدافئة ثقةٌ واحترام، والمفرِطة في القوّة محاولة هيمنة، والرخوة الباردة تردّد أو نفور، ومن يقلب كفّه فوق كفّك يريد السيطرة. صافِح بثبات معتدل، نظرةٍ في العين، وابتسامةٍ صادقة — تبني انطباعاً أوّلَ يصعب محوه.", deep:"المصافحة تنقل في ثانيتين ما يحتاج الكلام دقائق لقوله، لأنها أول تلامس جسديّ مباشر. خمسة أنماط تتكرّر:\n• المتوازنة: ضغطٌ معتدل، كفٌّ عموديّ، جفافٌ ودفء — تقول 'أنا واثق وأحترمك'.\n• الساحقة: قبضةٌ تؤلم — غالباً قلقٌ يتخفّى في صورة قوّة، أو رغبة هيمنة.\n• الرخوة ('السمكة الميتة'): بلا ضغط — تردّد، تحفّظ، أو عدم رغبة في التواصل.\n• قلب الكفّ للأعلى: من يجعل كفّه فوق كفّك يضع نفسه في موضع الأعلى لاشعورياً.\n• اليد المبلّلة الباردة: علامة توتّر (الجهاز العصبيّ يفرز العرق تحت الضغط).\nالأهمّ أن تقرأها مع السياق: ثقافات تصافح بقوّة وأخرى بلطف. وأن تضبط مصافحتك أنت: ضغطٌ يساوي ضغط الطرف الآخر تقريباً، نظرةٌ في العين، وثانيةٌ أو اثنتان لا أكثر.", practice:"اليوم: لاحظ نوع مصافحة من تلقاهم، وانتبه أن تكون مصافحتك ثابتة دافئة لا مفرِطة.", mantra:"في أول لمسةٍ ينعقد أوّل حكم." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"المكان والوضعية ولغة السلطة", teach:"الجسد الواثق يأخذ مساحته: كتفان مفتوحان، وقفةٌ مستقرّة، يدان ظاهرتان. والمنغلق ينكمش: ذراعان مطويّتان، كتفان مرفوعان. من يجلس في صدر الطاولة أو يتّكئ بثقة يرسل سلطة. لا تنكمش حين تريد أن تُحترَم؛ خذ مساحتك بهدوءٍ لا بعدوان.", deep:"السلطة في لغة الجسد ليست عدواناً، بل 'انفتاحاً واستقراراً'. تأمّل الفرق:\n• الانفتاح مقابل الانغلاق: الصدر المكشوف، اليدان الظاهرتان، الكتفان المسترخيان = ثقة وأمان داخليّ. الذراعان المطويّتان والكتفان المرفوعان = حماية وتوتّر.\n• الثبات مقابل التململ: القدمان الراسختان، الحركة البطيئة المقصودة = هدوء وسيطرة. كثرة الحركة والاهتزاز = قلق.\n• المكان: من يجلس في صدر الطاولة أو يقف بينما يجلس الآخرون يتصدّر المشهد. والمساحة التي يشغلها الجسد ترتبط مباشرةً بإحساسه بالمكانة.\n• اليدان: إظهار راحتي اليدين إشارة صدقٍ وانفتاح قديمة ('لا أخفي سلاحاً')؛ إخفاؤهما في الجيبين يقلّل من حضورك.\nالمبدأ: لا تتمدّد بعدوانٍ يستفزّ، ولا تنكمش بخوفٍ يُستضعَف — خذ مساحتك الطبيعية بهدوءٍ واثق.", practice:"في اجتماع اليوم: افتح كتفيك، أبقِ يديك ظاهرتين، ولا تنكمش على نفسك.", mantra:"من أخذ مساحته بثقةٍ أُعطِي هيبته." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"عناقيد الاهتمام والملل", teach:"اقرأ التفاعل لا الكلمة: الاهتمام عنقودٌ من الانحناء إليك، رأسٌ مائل، حاجبان مرفوعان قليلاً، قدمان نحوك. والملل عنقودٌ من النظر بعيداً، عبثٍ بشيء، جسدٍ يميل للخلف أو نحو الباب. حين ترى عناقيد الملل، غيّر الموضوع أو أنهِ بلباقة — لا تطارد انتباهاً غادر.", deep:"الانتباه يتسرّب من الجسد قبل أن يُعلنه اللسان بدقائق. اقرأ 'العناقيد' لا الإشارة الواحدة:\nعنقود الاهتمام:\n• الجذع والقدمان يتّجهان نحوك.\n• إمالة الرأس قليلاً (علامة إصغاء).\n• رفع الحاجبين للحظة، واتّساع طفيف في العين.\n• تطابق تعابيره مع كلامك (يبتسم حين تبتسم).\nعنقود الملل أو الانسحاب:\n• الجسد يميل للخلف أو يستدير نحو الباب.\n• العبث بالهاتف أو القلم، النظر للساعة.\n• إجاباتٌ قصيرة، رأسٌ يسند على اليد بثقل.\n• قدمان تتّجهان بعيداً (تذكّر: القدمان أصدق الأجزاء).\nالحكمة العملية: حين ترى عنقود الملل، لا تطارد الانتباه بكلامٍ أكثر — اطرح سؤالاً يعيده، أو غيّر الموضوع، أو أنهِ بلباقة. مطاردة انتباهٍ غادر تُضعف حضورك.", practice:"اليوم: راقب متى يميل محدّثك إليك (اهتمام) ومتى يبتعد جسده (ملل)، وعدّل حديثك تبعاً لذلك.", mantra:"الجسد يقول 'كمّل' أو 'كفى' قبل اللسان." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"الصوت نصف الرسالة", teach:"ليست لغة الجسد حركةً فقط، بل صوتاً أيضاً: النبرة الهادئة المنخفضة سلطةٌ وثقة، والسريعة الحادّة توتّر، والصمت المدروس قبل الجواب وزنٌ وثبات. من يرفع طبقة صوته في نهاية الجمل يبدو متردّداً يطلب الموافقة. تحكّم في إيقاعك ونبرتك تتحكّم في الانطباع.", deep:"الصوت 'لغة جسدٍ مسموعة' (يسمّيها العلماء paralanguage)، وقد تحمل النبرة معنىً يناقض الكلمات. عناصرها:\n• الطبقة (Pitch): الصوت المنخفض الهادئ يُقرأ كثقةٍ وسلطة؛ الصوت الحادّ المرتفع كتوتّرٍ أو انفعال. التوتّر يشدّ الحبال الصوتية فترتفع الطبقة لاإرادياً.\n• الإيقاع (Pace): الكلام السريع المتدفّق علامة قلقٍ أو رغبةٍ في إنهاء الموقف؛ الكلام المتمهّل علامة ثقةٍ وتحكّم. أبطئ عمداً لتبدو أكثر رسوخاً.\n• الصمت (Pause): الوقفة المقصودة قبل الجواب تقول 'أنا أفكّر، لست مضطراً للاندفاع' — وهي من أقوى أدوات الحضور. أغلب الناس يهربون من الصمت بالثرثرة.\n• نبرة السؤال في نهاية الجملة (Uptalk): رفع الطبقة في آخر الجملة الخبرية يجعلها تبدو وكأنها سؤالٌ يطلب موافقة — يُضعف الثقة. أنهِ جملك بطبقةٍ نازلةٍ حازمة.\nالتدرّب على هذه الأربعة يغيّر كيف يسمعك الناس أكثر مما تغيّره الكلمات نفسها.", practice:"اليوم: في موقف مهمّ، أبطئ كلامك، اخفض نبرتك قليلاً، واسمح لنفسك بصمتةٍ قبل الجواب.", mantra:"الصوت الهادئ المتمهّل يفرض احترامه." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"إشارات عدم الراحة في التفاوض", teach:"في التفاوض والبيع، الجسد يتسرّب منه ما لا يقوله اللسان: تراجعٌ مفاجئ عند رقمٍ معيّن، لمس الرقبة عند سؤال، تململٌ على المقعد، أو نظرةٌ سريعة نحو المخرج. هذه نقاط 'حرارة' تكشف أين يضعف أو يقلق الطرف الآخر. لاحظها بهدوء واستكشفها بسؤال، لا تستغلّها بقسوة.", deep:"في التفاوض، النقاط التي يقلق عندها الطرف الآخر تكشف حدوده الحقيقية. ابحث عن 'تغيّرٍ مفاجئ' عند ذكر رقمٍ أو شرطٍ معيّن:\n• إشارات التهدئة الذاتية: لمس الرقبة (نقطة الودجة الحسّاسة)، فرك اليدين، شدّ الياقة، لمس الشفتين — ترتفع فجأة عند بندٍ يقلقه.\n• الحواجز: وضع جسمٍ بينكما (كوب، حقيبة)، طيّ الذراعين، الميل للخلف عند نقطةٍ معيّنة.\n• التسريبات: نظرةٌ سريعة نحو الباب (رغبة هروب)، ابتلاعٌ ملحوظ، حبسٌ للنفَس، تجمّدٌ لحظيّ.\n• علامات الرضا (المقابلة): كتفان يهبطان استرخاءً، انحناءٌ للأمام، يدان مفتوحتان — تعني أنك قريبٌ من اتفاقٍ مريح.\nالاستخدام الأخلاقيّ: هذه ليست أدوات للضغط القاسي، بل بوصلة. حين ترى التوتّر، اسأل بلطف ('يبدو أن هذه النقطة تهمّك، لنتكلّم عنها') — فتبني ثقةً وتصل لاتفاقٍ يرضي الطرفين، لا غلبةً تُورِث ضغينة.", practice:"في أي نقاشٍ تفاوضيّ اليوم، لاحظ متى يتغيّر جسد الطرف الآخر — وأيّ نقطةٍ أثارت ذلك.", mantra:"عند كل توتّرٍ جسديّ نقطةُ حقيقةٍ مخبوءة." },
  { pillar:"لغة الجسد", icon:"🕴️", color:"#0891b2", title:"كن صادق الإشارة، لا مزيّفها", teach:"يمكنك ضبط جسدك لتبدو واثقاً، لكن أقوى حضورٍ هو حين تتطابق إشاراتك مع داخلك حقاً. حين تكذب لغة جسدك على مشاعرك يلتقط الناس التنافر لاشعورياً ويفقدون الثقة. بدل تزييف الثقة، اصنعها: تنفّس، صدق نيّتك، وحضّر نفسك — فينطق جسدك بصدقٍ تلقائيّ يأسر القلوب.", deep:"الناس يلتقطون 'التنافر' (incongruence) لاشعورياً: حين تبتسم شفتاك بينما عيناك جامدتان، أو تقول 'أنا مرتاح' وجسدك متيبّس — يشعر من أمامك بشيءٍ 'غير صادق' دون أن يعرف لماذا، فتنهار الثقة. لذلك التزييف الكامل يكاد يكون مستحيلاً وطويل الأمد.\nالطريق الأقوى هو 'الصدق المُحضَّر':\n• الجسد يؤثّر في الداخل: الوقوف منتصباً والتنفّس البطيء العميق يخفضان هرمون التوتر فعلياً ويولّدان شعوراً حقيقياً بالهدوء (مبدأ 'تصرّف حتى تصبح'). فأنت لا تكذب، بل تهيّئ حالةً صادقة.\n• صدق النيّة: ادخل الموقف بنيّة الخدمة أو الفهم لا الانتصار — فتسترخي ملامحك تلقائياً.\n• التحضير: من يعرف ما سيقول ويثق بقيمته لا يحتاج لتمثيل الثقة؛ تنطق بها جوارحه.\nالخلاصة: لا تضبط جسدك لتخدع، بل اضبط حالتك ليصدُق جسدك. الحضور الحقيقيّ يأسر أضعاف ما يأسره أيّ أداءٍ متقَن.", practice:"قبل لقاء اليوم: بدل تمثيل الثقة، هدّئ نفسك واصدُق نيّتك، ودع جسدك يعبّر بصدق.", mantra:"الحضور الصادق أقوى من أيّ تمثيل." },
];

