const LEARN_POOL = [
  { topic:"تداول وأسواق", title:"اتّبع الاتجاه لا رأيك", teach:"السوق لا يهتمّ برأيك. أنجح المتداولين لا يتوقّعون، بل يتبعون. حين يكون السعر فوق متوسطاته الصاعدة، اشترِ القوة؛ وحين ينهار الاتجاه، ابتعد. رأيك المخالف للسوق يكلّفك مالاً.", deep:"القاعدة: «الاتجاه صديقك حتى ينحني». لا تجادل الرسم البياني — هو دفتر الحقيقة.", practice:"اليوم، قبل أي صفقة، اسأل: هل أتداول مع الاتجاه أم ضدّه؟ إن كان ضدّه، لا تدخل.", mantra:"تداول ما تراه لا ما تتمنّاه." },
  { topic:"تداول وأسواق", title:"وقف الخسارة قبل الدخول", teach:"لا تدخل صفقة دون أن تعرف أين ستخرج إن أخطأت. تحديد الخسارة سلفاً يحوّل الخوف إلى خطّة. من يدخل بلا وقف يترك مصيره للعاطفة.", deep:"حدّد الوقف عند المستوى الذي يُثبت أن فكرتك خاطئة — لا عند رقم يريحك نفسياً.", practice:"في صفقتك القادمة اكتب سعر الوقف قبل الشراء، والتزم به بلا نقاش.", mantra:"من لا يعرف مخرجه لا يملك خطّة." },
  { topic:"تداول وأسواق", title:"الحجم يكشف الحقيقة", teach:"السعر يكذب أحياناً، والحجم نادراً. اختراق بلا حجم فخّ، واختراق بحجم قوي نيّة حقيقية. تعلّم أن تقرأ الحجم كما تقرأ نبرة صوت المتكلم.", deep:"اشترِ الاختراق حين يفوق الحجم ١.٤ ضعف متوسطه — القوة تحتاج شهوداً.", practice:"راقب سهماً يخترق قمّة اليوم، وتحقّق: هل الحجم يؤكّد أم يخذل؟", mantra:"الاختراق بلا حجم كلام بلا فعل." },
  { topic:"إدارة المال والمخاطر", title:"قاعدة الواحد بالمئة", teach:"لا تخاطر بأكثر من ١٪ من حسابك في صفقة واحدة. هكذا تنجو من عشر صفقات خاسرة متتالية وتبقى في اللعبة. البقاء أولاً، ثم الربح.", deep:"المحترف يفكّر في كم يخسر قبل كم يربح. حماية رأس المال هي المهنة كلّها.", practice:"احسب ١٪ من حسابك الآن، واجعله سقفاً لخسارة أي صفقة اليوم.", mantra:"احمِ رأس المال يحمِك السوق." },
  { topic:"إدارة المال والمخاطر", title:"عائد لمخاطرة اثنين لواحد", teach:"لا تأخذ صفقة ربحها المحتمل أقلّ من ضعف خسارتها. بهذه القاعدة تربح حتى لو أصبت في أربع صفقات من عشر. الرياضيات تعمل لصالحك لا ضدّك.", deep:"صفقة ربحها ٢ وخسارتها ١ تجعل نسبة الإصابة ٤٠٪ كافية للربح على المدى.", practice:"قبل أي دخول، قِس المسافة للهدف والمسافة للوقف — ارفض ما دون ٢:١.", mantra:"لا تلعب لعبة رياضياتها ضدّك." },
  { topic:"إدارة المال والمخاطر", title:"ادفع لنفسك أولاً", teach:"الثروة ليست ما تكسب بل ما تحتفظ به. جنِّب نسبة من كل دخل للاستثمار قبل أن تنفق. من يدّخر ما يتبقّى لا يتبقّى له شيء.", deep:"اجعل الادخار تلقائياً — القرار مرّة واحدة أقوى من الإرادة كل يوم.", practice:"حوّل مبلغاً للادخار اليوم قبل أي إنفاق، مهما كان صغيراً.", mantra:"ادّخر أولاً، وأنفق ما تبقّى." },
  { topic:"الانضباط والعادات", title:"اجعل العادة سهلة", teach:"لا تعتمد على إرادتك، بل على بيئتك. قرّب العادة الجيدة خطوة وأبعد السيئة خطوة. ضع كتابك على وسادتك وهاتفك في غرفة أخرى — البيئة تقود السلوك.", deep:"الإرادة تنفد؛ التصميم الذكي للبيئة يبقى. اجعل الصواب أسهل طريق.", practice:"غيّر شيئاً واحداً في محيطك اليوم ليجعل عادة جيدة أسهل بخطوة.", mantra:"صمّم بيئتك تصمّم نفسك." },
  { topic:"الانضباط والعادات", title:"قاعدة الدقيقتين", teach:"حين تتهرّب من مهمّة، ابدأها لدقيقتين فقط. البدء أصعب من الاستمرار. غالباً ستكمل، وإن لم تفعل فقد كسرت حاجز التسويف.", deep:"الحركة تولّد الدافع، لا العكس. لا تنتظر الحماس — اصنعه بالفعل.", practice:"المهمّة التي تؤجّلها الآن — افعلها دقيقتين فقط، الآن.", mantra:"ابدأ صغيراً يكتمل الكبير." },
  { topic:"الانضباط والعادات", title:"لا تفوّت مرّتين", teach:"الكمال مستحيل، لكن العودة السريعة ممكنة. أن تخطئ يوماً حادث؛ أن تخطئ يومين بداية انهيار. القوّة في الرجوع فوراً لا في عدم السقوط.", deep:"البطل ليس من لا يزلّ، بل من ينهض قبل أن تبرد قدمه.", practice:"إن فاتتك عادة أمس، أنجزها اليوم بلا جلد للنفس.", mantra:"اسقط مرّة، وانهض في الحال." },
  { topic:"علم النفس", title:"سمِّ الشعور تُضعفه", teach:"حين تسمّي غضبك أو خوفك بوضوح، ينتقل عقلك من ردّ الفعل إلى الوعي. المشاعر التي لا تُسمّى تحكمك؛ والتي تُسمّى تخدمك.", deep:"«أنا أشعر بالقلق» أقوى من أن تكون القلق. المسافة بينك وبين الشعور هي حرّيتك.", practice:"عند أول انفعال اليوم، توقّف وسمِّ الشعور بكلمة واحدة قبل أن تتصرّف.", mantra:"ما تسمّيه لا يحكمك." },
  { topic:"علم النفس", title:"الفجوة بين المثير والاستجابة", teach:"بين ما يحدث لك وردّ فعلك مساحة. في تلك المساحة قوّتك وحرّيتك واختيارك. اتّسع تلك الفجوة بنَفَسٍ واحد تتغيّر حياتك.", deep:"الحيوان يتفاعل، والإنسان يستطيع أن يستجيب. اختر أن تكون إنساناً.", practice:"قبل أي ردّ مهمّ اليوم، خذ نفساً عميقاً واحداً أولاً.", mantra:"بين الحدث وردّك… أنت." },
  { topic:"علم النفس", title:"الامتنان يطرد القلق", teach:"لا يجتمع في القلب قلقٌ وامتنان في لحظة واحدة. الامتنان قرار لا شعور — تختاره حتى في الضيق فينقلب حالك.", deep:"الدماغ يبحث عمّا تدرّبه عليه؛ درّبه على النِّعم لا النقص.", practice:"اكتب ثلاثة أشياء محدّدة أنت ممتنّ لها قبل النوم.", mantra:"الشاكر لا يعرف الطريق إلى اليأس." },
  { topic:"الحكمة والإيمان", title:"استجب ولا تتفاعل", teach:"ردّ الفعل السريع نادراً ما يكون حكيماً. الحكيم يتمهّل، يفهم، ثم يتحرّك. السرعة في الغضب ندمٌ مؤجّل.", deep:"«ليس الشديد بالصُّرعة، إنما الشديد الذي يملك نفسه عند الغضب».", practice:"في خلافك القادم، أنصت كاملاً قبل أن تنطق بكلمة.", mantra:"املك نفسك تملك الموقف." },
  { topic:"الحكمة والإيمان", title:"الرضا كنز لا يفنى", teach:"الغنى غنى النفس لا كثرة المال. من رضي بما قُسم له عاش ملكاً، ومن طمع بلا حدّ عاش فقيراً وإن ملك الدنيا.", deep:"القناعة لا تعني التوقّف عن السعي، بل الطمأنينة أثناءه.", practice:"اذكر اليوم نعمة تملكها ويتمنّاها غيرك، وقل: الحمد لله.", mantra:"من رضي فله الرضا." },
  { topic:"الحكمة والإيمان", title:"التوكّل بعد الأخذ بالأسباب", teach:"اعقل ثم توكّل. افعل ما بوسعك بإتقان، ثم سلّم النتيجة لله بقلب مطمئن. الجمع بين الجدّ والتسليم هو راحة العقلاء.", deep:"القلق يأتي من محاولة التحكّم فيما ليس بيدك؛ التوكّل يعيد الأمور لنصابها.", practice:"أنجز مهمّتك اليوم بأفضل ما تقدر، ثم اترك القلق على النتيجة.", mantra:"ابذل ما تملك، وسلّم ما لا تملك." },
  { topic:"القيادة", title:"قُد بالهدوء", teach:"من حولك يشعرون بطاقتك قبل كلماتك. القائد الهادئ يصنع فريقاً هادئاً، والمتوتّر يَعدي توتّره. سكينتك رسالة أبلغ من أي خطاب.", deep:"في الأزمة، أوّل ما يبحث عنه الناس هو وجه القائد — ليكن ثابتاً.", practice:"في لحظتك المتوتّرة القادمة، اخفض صوتك وأبطئ كلامك عمداً.", mantra:"هدوؤك يهدّئ من حولك." },
  { topic:"القيادة", title:"المسؤولية الكاملة", teach:"حين يسوء أمر، انظر في المرآة أولاً. اللوم يريحك لحظة ويضعفك دائماً؛ المسؤولية تؤلم لحظة وتقوّيك دائماً. من يملك المشكلة يملك الحل.", deep:"القائد لا يقول «هم أخطأوا»، بل «كيف أصلح أنا؟».", practice:"تحمّل مسؤولية خطأ واحد اليوم بلا عذر — فقط الخطوة التالية.", mantra:"امتلك المشكلة تمتلك الحل." },
  { topic:"القيادة", title:"معيارك ما تسكت عنه", teach:"لا تحصل على ما تتمنّى، بل على ما تقبل. كل سلوك سيّئ تتغاضى عنه يصبح معياراً جديداً. ارفع سقفك بهدوء بالقدوة لا بالصراخ.", deep:"الصمت عن الخطأ موافقة صامتة عليه.", practice:"حدّد أمراً تتساهل فيه منذ مدّة، وعالجه بهدوء اليوم.", mantra:"ما تتسامح معه يصير قاعدتك." },
  { topic:"الأب والزوج", title:"الحضور أثمن من الهدايا", teach:"لن يتذكّر أطفالك الهدايا، بل سيتذكّرون إن كنت حاضراً. دقيقة حضور كامل خيرٌ من ساعة مشتّتة بالهاتف. الأطفال يهجّون الحبّ: و-ق-ت.", deep:"الانتباه الكامل أندر هدية في زمن المشتّتات — امنحها من تحبّ.", practice:"امنح أطفالك ١٥ دقيقة حضوراً كاملاً اليوم، والهاتف في غرفة أخرى.", mantra:"وجودك أبلغ من عطائك." },
  { topic:"الأب والزوج", title:"قُل تقديرك بصوتٍ عالٍ", teach:"من تحبّ لا يقرأ أفكارك. الامتنان الصامت بلا أثر. قل لزوجتك وأبنائك ما تقدّره فيهم بالتحديد — الكلمة الطيّبة تبني ما يهدمه الصمت.", deep:"ما تلاحظه وتمدحه ينمو؛ ما تتجاهله يذبل.", practice:"أخبر شخصاً تحبّه اليوم بشيء محدّد تقدّره فيه.", mantra:"التقدير الصامت لا يصل." },
  { topic:"الأب والزوج", title:"أنصت لتفهم لا لتُصلح", teach:"غالباً يريد من يشكو أن يُسمع لا أن يُحَلّ. اسأل: «تريد مساعدة أم فقط أن تتكلّم؟». أحياناً أذنك أنفع من كل حلولك.", deep:"الإنصات الحقيقي هدية نادرة؛ أكثر الناس ينتظرون دورهم في الكلام لا الفهم.", practice:"حين يشاركك أحدهم همّاً اليوم، أنصت كاملاً قبل أي حلّ.", mantra:"أنصت أولاً، فالحلّ يأتي لاحقاً." },
];

export default function CoachTab({ C, MONO, SANS }) {
  const [section, setSection] = useState("today"); // today | program | habits | reflect
  const [form, setForm] = useState({
    energy: "7", sleep: "7", mood: "🙂",
    focus: "", struggle: "", win: "", money: "", family: "",
  });
  const [plan, setPlan] = useState(() => { try { return JSON.parse(localStorage.getItem(COACH_KEY)) || null; } catch { return null; } });
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");

  // Program progress
  const [lessonDone, setLessonDone] = useState(() => { try { return JSON.parse(localStorage.getItem("coach_lessons_done")) || {}; } catch { return {}; } });
  const [openLesson, setOpenLesson] = useState(null);
  const [collapsedCats, setCollapsedCats] = useState({});
  const [pillarTab, setPillarTab] = useState("الكل");
  const toggleLesson = (i) => { const n = { ...lessonDone, [i]: !lessonDone[i] }; setLessonDone(n); localStorage.setItem("coach_lessons_done", JSON.stringify(n)); };

  // ── Audio: read the lesson aloud and auto-advance to the next ──
  const [audioIdx, setAudioIdx] = useState(null);   // lesson index currently being spoken
  const [voices, setVoices] = useState([]);
  const [voiceURI, setVoiceURI] = useState(() => (typeof localStorage !== "undefined" && localStorage.getItem("coach_voice")) || "");
  const [rate, setRate] = useState(() => Number(typeof localStorage !== "undefined" && localStorage.getItem("coach_rate")) || 0.95);
  useEffect(() => {
    if (typeof window === "undefined" || !window.speechSynthesis) return;
    const load = () => setVoices(window.speechSynthesis.getVoices() || []);
    load();
    window.speechSynthesis.onvoiceschanged = load;
  }, []);
  // Prefer the user's pick; else the most natural Arabic voice (online/network voices are far less robotic than local ones).
  const pickVoice = () => {
    if (voiceURI) { const v = voices.find(x => x.voiceURI === voiceURI); if (v) return v; }
    const ar = voices.filter(v => /^ar/i.test(v.lang));
    const online = ar.filter(v => v.localService === false);   // network voices sound much better
    return online.find(v => /male|majed|na?yf|hamed|tarik|fahad/i.test(v.name)) || online[0]
        || ar.find(v => /male|majed|na?yf|hamed|tarik|fahad/i.test(v.name)) || ar[0] || null;
  };
  const speakLesson = (idx) => {
    if (typeof window === "undefined" || !window.speechSynthesis) return;
    const l = COACH_LESSONS[idx];
    if (!l) { setAudioIdx(null); return; }
    const ss = window.speechSynthesis;
    ss.cancel();
    setOpenLesson(idx);
    setCollapsedCats(p => ({ ...p, [l.pillar]: false }));
    setAudioIdx(idx);
    const text = [l.title, l.teach, l.deep || "", "التمرين: " + l.practice, l.mantra || ""].filter(Boolean).join("، ");
    const u = new SpeechSynthesisUtterance(text);
    const v = pickVoice();
    if (v) u.voice = v;
    u.lang = v ? v.lang : "ar-SA";
    u.rate = rate; u.pitch = 0.9;
    u.onend = () => { if (idx + 1 < COACH_LESSONS.length) speakLesson(idx + 1); else setAudioIdx(null); };
    u.onerror = () => setAudioIdx(null);
    ss.speak(u);
  };
  const stopSpeak = () => { if (window.speechSynthesis) window.speechSynthesis.cancel(); setAudioIdx(null); };
  useEffect(() => () => { if (typeof window !== "undefined" && window.speechSynthesis) window.speechSynthesis.cancel(); }, []);
  const arVoices = voices.filter(v => /^ar/i.test(v.lang));

  // Habits (per day)
  const todayKey = new Date().toISOString().slice(0,10);
  const [habits, setHabits] = useState(() => { try { return JSON.parse(localStorage.getItem("coach_habits")) || {}; } catch { return {}; } });
  const toggleHabit = (hid) => {
    const day = habits[todayKey] || {};
    const nd = { ...day, [hid]: !day[hid] };
    const n = { ...habits, [todayKey]: nd };
    setHabits(n); localStorage.setItem("coach_habits", JSON.stringify(n));
  };
  const habitStreak = (hid) => {
    let streak = 0;
    for (let i = 0; i < 365; i++) {
      const d = new Date(); d.setDate(d.getDate() - i);
      const k = d.toISOString().slice(0,10);
      if (habits[k]?.[hid]) streak++; else if (i > 0) break; else break;
    }
    return streak;
  };

  // Reflection journal
  const [reflectText, setReflectText] = useState("");
  const [reflections, setReflections] = useState(() => { try { return JSON.parse(localStorage.getItem("coach_reflect")) || []; } catch { return []; } });
  const saveReflection = () => {
    if (!reflectText.trim()) return;
    const n = [{ id: Date.now(), text: reflectText.trim(), date: new Date().toLocaleDateString() }, ...reflections].slice(0, 120);
    setReflections(n); localStorage.setItem("coach_reflect", JSON.stringify(n)); setReflectText("");
  };

  // ── Learn Something New: AI-generated fresh lessons ──
  const [learned, setLearned] = useState(() => { try { return JSON.parse(localStorage.getItem("coach_learned")) || []; } catch { return []; } });
  const [learnLoading, setLearnLoading] = useState(false);
  const [learnErr, setLearnErr] = useState("");
  // Free & offline: pick a fresh lesson from the built-in library (no API key, no cost).
  const learnNew = () => {
    setLearnErr("");
    const seen = new Set(learned.map(x => x.title));
    let pool = LEARN_POOL.filter(l => !seen.has(l.title));
    if (!pool.length) pool = LEARN_POOL;              // all seen → allow repeats
    const pick = pool[Math.floor(Math.random() * pool.length)];
    if (!pick) { setLearnErr("لا دروس متاحة."); return; }
    const item = { id: Date.now(), ...pick };
    const n = [item, ...learned].slice(0, 100);
    setLearned(n); localStorage.setItem("coach_learned", JSON.stringify(n));
  };
  const speakLearned = (item) => {
    if (typeof window === "undefined" || !window.speechSynthesis) return;
    const ss = window.speechSynthesis; ss.cancel();
    const text = [item.title, item.teach, item.deep || "", "التمرين: " + (item.practice || ""), item.mantra || ""].filter(Boolean).join("، ");
    const u = new SpeechSynthesisUtterance(text);
    const v = pickVoice(); if (v) u.voice = v;
    u.lang = v ? v.lang : "ar-SA"; u.rate = rate; u.pitch = 0.9;
    ss.speak(u);
  };
  const deleteLearned = (id) => { const n = learned.filter(x => x.id !== id); setLearned(n); localStorage.setItem("coach_learned", JSON.stringify(n)); };

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const generate = async () => {
    setLoading(true); setErr("");
    const prompt = `أنت مدرّب شخصي حكيم ومهتمّ لرجل يريد أن يصبح أكثر انضباطاً وثراءً وحكمة، وقائداً وأباً وزوجاً أفضل. يدير معرض سيارات مستعملة ويتداول الأسهم.

مراجعة اليوم:
- الطاقة: ${form.energy}/10، النوم: ${form.sleep}/10، المزاج: ${form.mood}
- تركيز اليوم الأهم: ${form.focus || "(غير محدّد)"}
- أكبر تحدٍّ الآن: ${form.struggle || "(غير محدّد)"}
- إنجاز أخير: ${form.win || "(غير محدّد)"}
- الوضع/الهدف المالي: ${form.money || "(غير محدّد)"}
- ملاحظة عائلية: ${form.family || "(غير محدّد)"}

أعطه خطة محدّدة وقوية لهذا اليوم. اكتب الرد بالكامل بالعربية، بهذا التنسيق تماماً مع هذه العناوين، 2-4 نقاط قصيرة لكل قسم، عملية وقابلة للتنفيذ اليوم (بلا حشو ولا نصائح عامة):

الأولويات:
خطوة مالية:
خطوة صحية:
خطوة عائلية:
حقيقة صعبة:

يجب أن تكون "الحقيقة الصعبة" جملة واحدة صادقة ومباشرة تتحدّاه. كن دافئاً لكن صريحاً. اجعل كل شيء مختصراً.`;

    try {
      const r = await fetch("/api/agent", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ prompt }) });
      const d = await r.json();
      if (d.output) {
        const out = { text: d.output.trim(), ts: new Date().toISOString(), date: new Date().toLocaleDateString() };
        setPlan(out); localStorage.setItem(COACH_KEY, JSON.stringify(out));
      } else throw new Error("no output");
    } catch (e) {
      // ── Smart rule-based coach (no AI key needed) ──
      const en = Number(form.energy), sl = Number(form.sleep);
      const lowEnergy = en <= 5 || sl <= 5;
      const lowMood = form.mood === "😤" || form.mood === "😔";
      const pick = arr => arr[new Date().getDate() % arr.length]; // rotates daily

      // الأولويات
      const pri = [];
      pri.push(form.focus ? `• ${form.focus} — هذا هو الشيء الوحيد. أنجزه قبل أن تلمس أي شيء آخر.` : "• حدّد شيئك الأهم الوحيد وأنهِه قبل الظهر.");
      pri.push(lowEnergy ? "• طاقتك منخفضة اليوم — اقطع قائمتك للنصف. احمِ طاقتك للشيء الوحيد المهم." : "• ابدأ بالأصعب: نفّذ أصعب مهمة أولاً ما دامت إرادتك قوية.");
      pri.push(pick([
        "• ضع الهاتف على وضع \"عدم الإزعاج\" في أول فترة عمل عميق.",
        "• اكتب أهم 3 مهام على ورقة. ما ليس في القائمة لا يحدث اليوم.",
        "• قل \"لا\" اليوم لشيء واحد لا يقدّمك للأمام.",
        "• اجمع مشتتاتك — تفقّد الرسائل في أوقات محددة، لا باستمرار.",
      ]));

      // المال
      const money = [];
      money.push(form.money ? `• ${form.money}` : "• انظر إلى رقم حقيقي واحد اليوم — السيولة، أو هامش، أو عميل ساخن. اعرفه تماماً.");
      money.push("• صفقات الضوء الأخضر فقط. خاطر بـ1٪. ضع وقف الخسارة قبل الدخول. لا صفقات انتقامية.");
      money.push(pick([
        "• المعرض: تابع مع عميل دافئ كنت تتجاهله.",
        "• حرّك شيئاً نحو الادخار/الاستثمار — العادة أهم من المبلغ.",
        "• اقطع مصروفاً متكرراً صغيراً لم تعد تلاحظه.",
        "• اسأل نفسك: هل كنت سأشتري هذا لو دفعت نقداً وجهاً لوجه؟ إن لا، فاتركه.",
      ]));

      // الصحة
      const health = [];
      health.push(lowEnergy ? "• النوم هو ميزتك الحقيقية — أخرج الهاتف من الغرفة، ونم قبل 30 دقيقة الليلة." : "• حرّك جسدك مرة: مشي 20 دقيقة أو تمرين سريع. غير قابل للتفاوض.");
      health.push(pick([
        "• اشرب الماء أول شيء — معظم الإرهاق هو جفاف.",
        "• وجبة صحية واحدة اليوم. لا تقرّر ولا تتداول وأنت جائع.",
        "• 5 أنفاس بطيئة قبل أول قرار كبير — الهدوء يغلب السرعة.",
        "• تعرّض للشمس 10 دقائق — يعيد ضبط طاقتك ومزاجك.",
      ]));

      // العائلة
      const fam = [];
      fam.push(form.family ? `• ${form.family}` : "• 15 دقيقة حضور كامل مع أطفالك — الهاتف في غرفة أخرى، بلا انتباه نصفي.");
      fam.push(pick([
        "• أخبر زوجتك بشيء محدّد تقدّره فيها — لا عام، بل محدّد.",
        "• اسأل طفلك سؤالاً حقيقياً واستمع فعلاً للجواب.",
        "• افعل شيئاً صغيراً لزوجتك دون أن تُطلب منك.",
        "• ضع الهاتف مقلوباً على العشاء. كن حاضراً بقلبك، لا بجسدك فقط.",
      ]));
      fam.push("• قُد بالهدوء — عائلتك تشعر بتوترك قبل أن تنطق بكلمة.");

      // حقيقة صعبة
      const truths = [
        "الانضباط ليس حماساً — هو فعل الشيء الممل حين لا ترغب فيه. افعل الممل اليوم.",
        "مشكلتك ليست في المعرفة بل في التنفيذ. أنت تعرف ما يجب فعله — اذهب وافعله.",
        "أطفالك لن يتذكروا المال الذي جنيته. سيتذكرون إن كنت حاضراً. اختر على هذا الأساس اليوم.",
        "الانشغال ليس كالفعالية. معظم قائمتك تهرّب. نفّذ المهمة المخيفة.",
        "لا يمكنك التغلب على سوء الانضباط بالتداول، ولا على العادات السيئة بالكسب. أصلح العادة يتبعها المال.",
        "الراحة هي العدو. الشيء الذي تتجنّبه هو بالضبط ما سيقدّم حياتك.",
        "الصبر يبني الثروة؛ والتسرّع يدمّرها. تمهّل اليوم — في التداول وفي البيت.",
      ];
      const hard = form.struggle
        ? `• لقد سمّيت ما يعيقك: "${form.struggle}". توقّف عن التفاوض معه. خطوة واحدة ملموسة ضدّه اليوم — الآن.`
        : `• ${pick(truths)}`;
      if (lowMood) fam.push("• مزاجك ثقيل اليوم؟ لا تتخذ قرارات كبيرة من مكان منخفض. ثبّت السفينة أولاً.");

      const fb = [
        "الأولويات:", ...pri, "",
        "خطوة مالية:", ...money, "",
        "خطوة صحية:", ...health, "",
        "خطوة عائلية:", ...fam, "",
        "حقيقة صعبة:", hard,
      ].join("\n");
      const out = { text: fb, ts: new Date().toISOString(), date: new Date().toLocaleDateString(), fallback: true };
      setPlan(out); localStorage.setItem(COACH_KEY, JSON.stringify(out));
    }
    setLoading(false);
  };

  // Parse the plan into sections for nice display
  const sections = (() => {
    if (!plan?.text) return [];
    const labels = ["الأولويات", "خطوة مالية", "خطوة صحية", "خطوة عائلية", "حقيقة صعبة"];
    const icons  = { "الأولويات":"🎯", "خطوة مالية":"💰", "خطوة صحية":"💪", "خطوة عائلية":"👨‍👩‍👧", "حقيقة صعبة":"🔥" };
    const cols   = { "الأولويات":C.accent, "خطوة مالية":C.green, "خطوة صحية":"#14b8a6", "خطوة عائلية":"#a855f7", "حقيقة صعبة":C.red };
    const out = [];
    const text = plan.text;
    labels.forEach((lab, i) => {
      const re = new RegExp(lab + "\\s*:?", "i");
      const m = text.match(re);
      if (!m) return;
      const start = m.index + m[0].length;
      let end = text.length;
      for (let j = i + 1; j < labels.length; j++) {
        const mm = text.match(new RegExp(labels[j] + "\\s*:?", "i"));
        if (mm && mm.index > start) { end = Math.min(end, mm.index); }
      }
      const body = text.slice(start, end).trim().replace(/^[-•\s]+/, "");
      out.push({ label: lab, icon: icons[lab], color: cols[lab], body });
    });
    return out;
  })();

  const inp = { background: C.surface, border: `1px solid ${C.border}`, borderRadius: 6, fontFamily: SANS, fontSize: 13, color: C.text, padding: "8px 10px", outline: "none", width: "100%", boxSizing: "border-box" };

  const doneCount = Object.values(lessonDone).filter(Boolean).length;
  const todayHabits = habits[todayKey] || {};
  const habitsDoneToday = COACH_HABITS.filter(h => todayHabits[h.id]).length;

  return (
    <div style={{ padding: "16px 20px", maxWidth: 860, margin: "0 auto", direction: "rtl" }}>
      <div style={{ marginBottom: 14 }}>
        <div style={{ fontFamily: SANS, fontSize: 22, fontWeight: 900, color: C.text }}>🧭 المدرّب</div>
        <div style={{ fontFamily: SANS, fontSize: 13, color: C.textDim, marginTop: 3, direction: "rtl" }}>
          الانضباط · المال · الحكمة · القيادة · الأبوّة · الزوجية — انمُ كل يوم
        </div>
      </div>

      {/* Section tabs */}
      <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap" }}>
        {[["today","☀️ اليوم"],["program",`📚 البرنامج (${doneCount}/${COACH_LESSONS.length})`],["learn","🎓 تعلّم جديد"],["habits",`✅ العادات (${habitsDoneToday}/${COACH_HABITS.length})`],["reflect","🧘 تأمّل"]].map(([id,l]) => (
          <button key={id} onClick={() => setSection(id)}
            style={{ background: section===id ? C.accent : C.surface, color: section===id ? "#fff" : C.textSec,
              border: `1px solid ${section===id ? C.accent : C.border}`, borderRadius: 8,
              fontFamily: SANS, fontSize: 13, fontWeight: 700, padding: "8px 14px", cursor: "pointer" }}>{l}</button>
        ))}
      </div>

      {/* ═══ TODAY ═══ */}
      {section === "today" && <>
      {/* Check-in form */}
      <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 10, padding: 16, marginBottom: 16 }}>
        <div style={{ fontFamily: SANS, fontSize: 12, fontWeight: 800, color: C.textDim, letterSpacing: "0.04em", marginBottom: 12, direction: "rtl" }}>أخبرني عن يومك</div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 12, marginBottom: 12, direction: "rtl" }}>
          {[["energy","الطاقة"],["sleep","النوم"]].map(([k,l]) => (
            <div key={k}>
              <div style={{ display: "flex", justifyContent: "space-between" }}>
                <span style={{ fontFamily: SANS, fontSize: 11, color: C.textDim }}>{l}</span>
                <span style={{ fontFamily: MONO, fontSize: 12, fontWeight: 700, color: C.accent }}>{form[k]}/10</span>
              </div>
              <input type="range" min="1" max="10" value={form[k]} onChange={e => set(k, e.target.value)} style={{ width: "100%", accentColor: C.accent }} />
            </div>
          ))}
          <div>
            <div style={{ fontFamily: SANS, fontSize: 11, color: C.textDim, marginBottom: 4 }}>المزاج</div>
            <div style={{ display: "flex", gap: 4 }}>
              {["😤","😔","😐","🙂","🔥"].map(m => (
                <button key={m} onClick={() => set("mood", m)}
                  style={{ fontSize: 18, background: form.mood===m ? `${C.accent}22` : "none", border: `1px solid ${form.mood===m ? C.accent : C.border}`, borderRadius: 6, padding: "2px 5px", cursor: "pointer" }}>{m}</button>
              ))}
            </div>
          </div>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, direction: "rtl" }}>
          <div><div style={{ fontFamily: SANS, fontSize: 11, color: C.textDim, marginBottom: 3 }}>🎯 تركيز اليوم الأهم</div><input value={form.focus} onChange={e=>set("focus",e.target.value)} placeholder="ما الأهم اليوم؟" style={{...inp, direction:"rtl"}}/></div>
          <div><div style={{ fontFamily: SANS, fontSize: 11, color: C.textDim, marginBottom: 3 }}>⚠️ أكبر تحدٍّ</div><input value={form.struggle} onChange={e=>set("struggle",e.target.value)} placeholder="ما الذي يعيقك؟" style={{...inp, direction:"rtl"}}/></div>
          <div><div style={{ fontFamily: SANS, fontSize: 11, color: C.textDim, marginBottom: 3 }}>✅ إنجاز أخير</div><input value={form.win} onChange={e=>set("win",e.target.value)} placeholder="شيء سار جيداً" style={{...inp, direction:"rtl"}}/></div>
          <div><div style={{ fontFamily: SANS, fontSize: 11, color: C.textDim, marginBottom: 3 }}>💰 هدف مالي</div><input value={form.money} onChange={e=>set("money",e.target.value)} placeholder="تركيز مالي اليوم" style={{...inp, direction:"rtl"}}/></div>
          <div style={{ gridColumn: "1 / -1" }}><div style={{ fontFamily: SANS, fontSize: 11, color: C.textDim, marginBottom: 3 }}>👨‍👩‍👧 ملاحظة عائلية</div><input value={form.family} onChange={e=>set("family",e.target.value)} placeholder="هل هناك شيء يشغلك مع عائلتك؟" style={{...inp, direction:"rtl"}}/></div>
        </div>
        <button onClick={generate} disabled={loading}
          style={{ marginTop: 14, width: "100%", background: C.accent, color: "#fff", border: "none", borderRadius: 8,
            fontFamily: SANS, fontSize: 15, fontWeight: 800, padding: "12px", cursor: loading ? "default" : "pointer" }}>
          {loading ? "⏳ جارٍ تدريبك…" : "🧭 درّبني اليوم"}
        </button>
        {err && <div style={{ fontFamily: SANS, fontSize: 12, color: C.red, marginTop: 6 }}>{err}</div>}
      </div>

      {/* Plan */}
      {plan && (
        <div style={{ direction: "rtl" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
            <span style={{ fontFamily: SANS, fontSize: 13, fontWeight: 800, color: C.text }}>خطتك — {plan.date}</span>
          </div>
          {sections.length > 0 ? sections.map(s => (
            <div key={s.label} style={{ background: C.card, border: `1px solid ${C.border}`, borderRight: `4px solid ${s.color}`, borderRadius: 10, padding: "12px 16px", marginBottom: 8 }}>
              <div style={{ fontFamily: SANS, fontSize: 13, fontWeight: 900, color: s.color, marginBottom: 6 }}>{s.icon} {s.label}</div>
              <div style={{ fontFamily: SANS, fontSize: 14, color: C.text, lineHeight: 1.6, whiteSpace: "pre-wrap" }}>{s.body}</div>
            </div>
          )) : (
            <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 10, padding: 16, fontFamily: SANS, fontSize: 14, color: C.text, lineHeight: 1.7, whiteSpace: "pre-wrap" }}>{plan.text}</div>
          )}
        </div>
      )}
      </>}

      {/* ═══ PROGRAM ═══ */}
      {section === "program" && (() => {
        // Group lessons by pillar, preserving each lesson's global index
        const groups = [];
        COACH_LESSONS.forEach((l, i) => {
          let g = groups.find(x => x.pillar === l.pillar);
          if (!g) { g = { pillar: l.pillar, icon: l.icon, color: l.color, items: [] }; groups.push(g); }
          g.items.push({ l, i });
        });
        const pillarCount = groups.length;
        return (
        <div style={{ direction: "rtl" }}>
          <div style={{ fontFamily: SANS, fontSize: 13, color: C.textDim, marginBottom: 12 }}>
            {COACH_LESSONS.length} درساً عبر {pillarCount} ركائز. اقرأ درساً كل يوم، طبّق التمرين، ثم علّم عليه. هكذا تنمو — مبدأ واحد في كل مرة.
          </div>
          {/* Progress bar */}
          <div style={{ height: 8, background: C.surface, borderRadius: 4, overflow: "hidden", marginBottom: 14 }}>
            <div style={{ width: `${doneCount/COACH_LESSONS.length*100}%`, height: "100%", background: C.green, transition: "width 0.4s" }} />
          </div>
          {/* Pillar tabs */}
          <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 14 }}>
            {[{ pillar: "الكل", icon: "📚", color: C.accent }, ...groups].map(g => {
              const active = pillarTab === g.pillar;
              return (
                <button key={g.pillar} onClick={() => setPillarTab(g.pillar)}
                  style={{ background: active ? g.color : C.surface, color: active ? "#fff" : C.textSec,
                    border: `1px solid ${active ? g.color : C.border}`, borderRadius: 8,
                    fontFamily: SANS, fontSize: 13, fontWeight: 800, padding: "7px 13px", cursor: "pointer", whiteSpace: "nowrap" }}>
                  {g.icon} {g.pillar}
                </button>
              );
            })}
          </div>
          {groups.filter(g => pillarTab === "الكل" || g.pillar === pillarTab).map(g => {
            const gDone = g.items.filter(x => lessonDone[x.i]).length;
            const collapsed = collapsedCats[g.pillar];
            const complete = gDone === g.items.length;
            return (
              <div key={g.pillar} style={{ marginBottom: 14 }}>
                {/* Category header */}
                <div onClick={() => setCollapsedCats(p => ({ ...p, [g.pillar]: !p[g.pillar] }))}
                  style={{ display: "flex", alignItems: "center", gap: 10, cursor: "pointer",
                    background: `${g.color}12`, border: `1px solid ${g.color}44`, borderRight: `5px solid ${g.color}`,
                    borderRadius: 10, padding: "10px 14px", marginBottom: 8 }}>
                  <span style={{ fontSize: 20 }}>{g.icon}</span>
                  <span style={{ flex: 1, fontFamily: SANS, fontSize: 16, fontWeight: 900, color: g.color }}>{g.pillar}</span>
                  <span style={{ fontFamily: MONO, fontSize: 12, fontWeight: 800, color: complete ? C.green : C.textDim }}>{gDone}/{g.items.length}{complete ? " ✓" : ""}</span>
                  <span style={{ fontFamily: MONO, fontSize: 12, color: C.textDim }}>{collapsed ? "▼" : "▲"}</span>
                </div>
                {!collapsed && g.items.map(({ l, i }) => (
                  <div key={i} style={{ background: C.card, border: `1px solid ${lessonDone[i] ? C.green+"55" : C.border}`,
                    borderRight: `4px solid ${l.color}`, borderRadius: 10, marginBottom: 8, marginRight: 14, overflow: "hidden",
                    opacity: lessonDone[i] ? 0.7 : 1 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "12px 14px", cursor: "pointer" }}
                      onClick={() => setOpenLesson(openLesson === i ? null : i)}>
                      <span style={{ fontSize: 16 }}>{l.icon}</span>
                      <div style={{ flex: 1, fontFamily: SANS, fontSize: 15, fontWeight: 800, color: C.text, textDecoration: lessonDone[i] ? "line-through" : "none" }}>{l.title}</div>
                      <button onClick={e => { e.stopPropagation(); toggleLesson(i); }}
                        style={{ background: lessonDone[i] ? C.green : "transparent", color: lessonDone[i] ? "#fff" : C.textDim,
                          border: `1px solid ${lessonDone[i] ? C.green : C.border}`, borderRadius: 6, width: 28, height: 28,
                          fontSize: 14, cursor: "pointer" }}>✓</button>
                      <span style={{ fontFamily: MONO, fontSize: 11, color: C.textDim }}>{openLesson === i ? "▲" : "▼"}</span>
                    </div>
                    {openLesson === i && (
                      <div style={{ padding: "0 44px 14px 14px" }}>
                        <div style={{ display: "flex", justifyContent: "flex-end", alignItems: "center", gap: 6, marginBottom: 8, flexWrap: "wrap" }}>
                          {(arVoices.length > 1 || voices.length > 0) && (
                            <select value={voiceURI} onClick={e => e.stopPropagation()} onChange={e => { e.stopPropagation(); setVoiceURI(e.target.value); localStorage.setItem("coach_voice", e.target.value); }}
                              title="اختر صوتاً — الأصوات أونلاين أوضح من الأصوات المحلية" style={{ fontFamily: SANS, fontSize: 11, color: C.textSec, background: C.surface, border: `1px solid ${C.border}`, borderRadius: 6, padding: "4px 6px", maxWidth: 160 }}>
                              <option value="">الصوت التلقائي</option>
                              {(arVoices.length ? arVoices : voices).map(v => <option key={v.voiceURI} value={v.voiceURI}>{v.name}{v.localService === false ? " ☁" : ""}</option>)}
                            </select>
                          )}
                          <select value={String(rate)} onClick={e => e.stopPropagation()} onChange={e => { e.stopPropagation(); const r = Number(e.target.value); setRate(r); localStorage.setItem("coach_rate", String(r)); }}
                            title="السرعة" style={{ fontFamily: MONO, fontSize: 11, color: C.textSec, background: C.surface, border: `1px solid ${C.border}`, borderRadius: 6, padding: "4px 6px" }}>
                            {[["0.8","0.8×"],["0.95","1×"],["1.15","1.15×"],["1.3","1.3×"]].map(([v,lbl]) => <option key={v} value={v}>{lbl}</option>)}
                          </select>
                          {audioIdx === i
                            ? <button onClick={e => { e.stopPropagation(); stopSpeak(); }} style={{ fontFamily: SANS, fontSize: 12, fontWeight: 800, padding: "5px 12px", borderRadius: 7, cursor: "pointer", border: `1px solid ${C.red}55`, background: `${C.red}14`, color: C.red }}>⏹ إيقاف</button>
                            : <button onClick={e => { e.stopPropagation(); speakLesson(i); }} title="استمع للدرس بصوتٍ ثم ينتقل تلقائياً للدرس التالي" style={{ fontFamily: SANS, fontSize: 12, fontWeight: 800, padding: "5px 12px", borderRadius: 7, cursor: "pointer", border: `1px solid ${l.color}55`, background: `${l.color}14`, color: l.color }}>🔊 استمع</button>}
                        </div>
                        <div style={{ fontFamily: SANS, fontSize: 15, color: C.text, lineHeight: 1.8, marginBottom: 12 }}>{l.teach}</div>
                        {l.deep && (
                          <div style={{ background: `${l.color}0a`, borderRight: `3px solid ${l.color}66`, borderRadius: 8, padding: "12px 14px", marginBottom: 12, direction: "rtl" }}>
                            <div style={{ fontFamily: SANS, fontSize: 11, fontWeight: 900, color: l.color, marginBottom: 8 }}>🔎 شرح أعمق</div>
                            <div style={{ fontFamily: SANS, fontSize: 14, color: C.text, lineHeight: 2, whiteSpace: "pre-line" }}>{l.deep}</div>
                          </div>
                        )}
                        <div style={{ background: `${l.color}12`, border: `1px solid ${l.color}33`, borderRadius: 8, padding: "10px 12px", marginBottom: 8 }}>
                          <div style={{ fontFamily: SANS, fontSize: 11, fontWeight: 900, color: l.color, marginBottom: 4 }}>✅ تمرين اليوم</div>
                          <div style={{ fontFamily: SANS, fontSize: 14, color: C.text, lineHeight: 1.6 }}>{l.practice}</div>
                        </div>
                        {l.mantra && (
                          <div style={{ textAlign: "center", padding: "8px 12px", fontFamily: SANS, fontSize: 14, fontWeight: 700,
                            fontStyle: "italic", color: l.color, background: `${l.color}08`, borderRadius: 8 }}>
                            ❝ {l.mantra} ❞
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            );
          })}
        </div>
        );
      })()}

      {/* ═══ LEARN SOMETHING NEW ═══ */}
      {section === "learn" && (
        <div style={{ direction: "rtl" }}>
          <div style={{ fontFamily: SANS, fontSize: 13, color: C.textDim, marginBottom: 14, lineHeight: 1.7 }}>
            درس جديد في كل ضغطة — تداول، مال، انضباط، حكمة، أو حياة. اضغط الزر ليولّد الذكاء درساً جديداً، ثم استمع إليه بصوتٍ عربي.
          </div>
          <div style={{ display: "flex", gap: 10, alignItems: "center", marginBottom: 16, flexWrap: "wrap" }}>
            <button onClick={learnNew} disabled={learnLoading}
              style={{ background: learnLoading ? C.surface : "#a855f7", color: learnLoading ? C.textDim : "#fff",
                border: "none", borderRadius: 9, fontFamily: SANS, fontSize: 14, fontWeight: 800,
                padding: "11px 22px", cursor: learnLoading ? "default" : "pointer" }}>
              {learnLoading ? "⏳ يولّد درساً…" : "🎓 تعلّم شيئاً جديداً"}
            </button>
            {learned.length > 0 && <span style={{ fontFamily: SANS, fontSize: 12, color: C.textDim }}>{learned.length} درس محفوظ</span>}
          </div>
          {learnErr && <div style={{ fontFamily: SANS, fontSize: 12, color: "#ef4444", marginBottom: 12 }}>⚠ {learnErr}</div>}
          {learned.length === 0 && !learnLoading && (
            <div style={{ fontFamily: SANS, fontSize: 13, color: C.textDim, padding: "30px 0", textAlign: "center" }}>
              لا دروس بعد — اضغط الزر أعلاه لأول درس.
            </div>
          )}
          {learned.map(item => (
            <div key={item.id} style={{ background: C.card, border: `1px solid ${C.border}`, borderRight: "3px solid #a855f7",
              borderRadius: 10, padding: 16, marginBottom: 12 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 10, marginBottom: 8 }}>
                <div style={{ fontFamily: SANS, fontSize: 16, fontWeight: 800, color: C.text }}>{item.title}</div>
                <div style={{ display: "flex", gap: 6, flexShrink: 0 }}>
                  <button onClick={() => speakLearned(item)} title="استمع"
                    style={{ fontFamily: SANS, fontSize: 12, fontWeight: 800, padding: "5px 11px", borderRadius: 7, cursor: "pointer",
                      border: "1px solid #a855f755", background: "#a855f714", color: "#a855f7" }}>🔊 استمع</button>
                  <button onClick={() => deleteLearned(item.id)} title="حذف"
                    style={{ fontFamily: SANS, fontSize: 12, padding: "5px 9px", borderRadius: 7, cursor: "pointer",
                      border: `1px solid ${C.border}`, background: C.surface, color: C.textDim }}>🗑</button>
                </div>
              </div>
              {item.topic && <div style={{ fontFamily: SANS, fontSize: 11, color: "#a855f7", marginBottom: 8, fontWeight: 700 }}>{item.topic}</div>}
              <div style={{ fontFamily: SANS, fontSize: 14, color: C.textSec, lineHeight: 1.8, marginBottom: item.deep ? 8 : 10 }}>{item.teach}</div>
              {item.deep && <div style={{ fontFamily: SANS, fontSize: 13, color: C.textDim, lineHeight: 1.8, marginBottom: 10 }}>{item.deep}</div>}
              {item.practice && <div style={{ fontFamily: SANS, fontSize: 13, color: C.text, background: C.surface, borderRadius: 8, padding: "9px 12px", marginBottom: 10, lineHeight: 1.7 }}>🎯 <b>التمرين:</b> {item.practice}</div>}
              {item.mantra && <div style={{ fontFamily: SANS, fontSize: 13, fontWeight: 700, color: "#a855f7", fontStyle: "italic" }}>“{item.mantra}”</div>}
            </div>
          ))}
        </div>
      )}

      {/* ═══ HABITS ═══ */}
      {section === "habits" && (
        <div style={{ direction: "rtl" }}>
          <div style={{ fontFamily: SANS, fontSize: 13, color: C.textDim, marginBottom: 14 }}>
            علّم على هذه يومياً. السلاسل تبني الرجل. تفوّت يوماً فتنكسر السلسلة — وهذا هو المغزى.
          </div>
          {COACH_HABITS.map(h => {
            const done = todayHabits[h.id];
            const streak = habitStreak(h.id);
            return (
              <div key={h.id} onClick={() => toggleHabit(h.id)}
                style={{ display: "flex", alignItems: "center", gap: 12, background: done ? `${h.color}12` : C.card,
                  border: `1px solid ${done ? h.color+"55" : C.border}`, borderRight: `4px solid ${h.color}`,
                  borderRadius: 10, padding: "12px 16px", marginBottom: 8, cursor: "pointer" }}>
                <div style={{ width: 26, height: 26, borderRadius: 6, border: `2px solid ${done ? h.color : C.border}`,
                  background: done ? h.color : "transparent", color: "#fff", display: "flex", alignItems: "center",
                  justifyContent: "center", fontSize: 15, flexShrink: 0 }}>{done ? "✓" : ""}</div>
                <span style={{ flex: 1, fontFamily: SANS, fontSize: 14, color: C.text, fontWeight: done ? 700 : 400 }}>{h.label}</span>
                {streak > 0 && <span style={{ fontFamily: MONO, fontSize: 12, fontWeight: 800, color: h.color }}>🔥 {streak} يوم</span>}
              </div>
            );
          })}
          <div style={{ marginTop: 14, textAlign: "center", fontFamily: SANS, fontSize: 13, color: C.textDim }}>
            اليوم: <span style={{ color: habitsDoneToday === COACH_HABITS.length ? C.green : C.accent, fontWeight: 800 }}>{habitsDoneToday}/{COACH_HABITS.length}</span>
            {habitsDoneToday === COACH_HABITS.length && " — يوم مثالي 🏆"}
          </div>

          {/* ── عادات سيئة تتخلّص منها ── */}
          <div style={{ marginTop: 22, marginBottom: 12, fontFamily: SANS, fontSize: 15, fontWeight: 900, color: C.text }}>🚫 عادات تتخلّص منها</div>
          <div style={{ fontFamily: SANS, fontSize: 13, color: C.textDim, marginBottom: 12 }}>
            علّم على العادة حين تتجنّبها اليوم. كل يوم نظيف يبني سلسلتك — والسلسلة تكسر العادة.
          </div>
          {COACH_BAD_HABITS.map(h => {
            const clean = todayHabits[h.id];
            const streak = habitStreak(h.id);
            return (
              <div key={h.id} onClick={() => toggleHabit(h.id)}
                style={{ display: "flex", alignItems: "center", gap: 12, background: clean ? `${h.color}12` : C.card,
                  border: `1px solid ${clean ? h.color+"55" : C.border}`, borderRight: `4px solid ${h.color}`,
                  borderRadius: 10, padding: "12px 16px", marginBottom: 8, cursor: "pointer" }}>
                <div style={{ width: 26, height: 26, borderRadius: 6, border: `2px solid ${clean ? h.color : C.border}`,
                  background: clean ? h.color : "transparent", color: "#fff", display: "flex", alignItems: "center",
                  justifyContent: "center", fontSize: 15, flexShrink: 0 }}>{clean ? "✓" : ""}</div>
                <span style={{ flex: 1, fontFamily: SANS, fontSize: 14, color: C.text, fontWeight: clean ? 700 : 400 }}>{h.label}</span>
                {clean && <span style={{ fontFamily: SANS, fontSize: 11, color: h.color }}>تجنّبتها ✓</span>}
                {streak > 0 && <span style={{ fontFamily: MONO, fontSize: 12, fontWeight: 800, color: h.color }}>🔥 {streak} يوم نظيف</span>}
              </div>
            );
          })}
        </div>
      )}

      {/* ═══ REFLECT ═══ */}
      {section === "reflect" && (
        <div style={{ direction: "rtl" }}>
          <div style={{ fontFamily: SANS, fontSize: 13, color: C.textDim, marginBottom: 12 }}>
            اختم يومك هنا. ما الذي سار جيداً، وما الذي ستغيّره، وما الذي تعلّمته. التأمّل هو حيث يتراكم النمو.
          </div>
          <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 10, padding: 14, marginBottom: 16 }}>
            <textarea value={reflectText} onChange={e => setReflectText(e.target.value)} rows={4}
              placeholder="اليوم… / أنا ممتنّ لـ… / غداً سأتحسّن في…"
              style={{ width: "100%", background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8,
                fontFamily: SANS, fontSize: 14, color: C.text, padding: "10px 12px", resize: "vertical", boxSizing: "border-box", outline: "none", direction: "rtl" }} />
            <button onClick={saveReflection}
              style={{ marginTop: 10, background: C.accent, color: "#fff", border: "none", borderRadius: 8,
                fontFamily: SANS, fontSize: 13, fontWeight: 700, padding: "10px 20px", cursor: "pointer" }}>
              💾 احفظ التأمّل
            </button>
          </div>
          {reflections.map(r => (
            <div key={r.id} style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 10, padding: "12px 14px", marginBottom: 8 }}>
              <div style={{ fontFamily: MONO, fontSize: 10, color: C.textDim, marginBottom: 4 }}>{r.date}</div>
              <div style={{ fontFamily: SANS, fontSize: 14, color: C.text, lineHeight: 1.5, whiteSpace: "pre-wrap" }}>{r.text}</div>
            </div>
          ))}
          {!reflections.length && <div style={{ textAlign: "center", padding: "30px 0", fontFamily: SANS, fontSize: 13, color: C.textDim }}>لا تأمّلات بعد. اختم يومك بواحد.</div>}
        </div>
      )}
    </div>
  );
}

